INSERT INTO `esami_questions` VALUES (117,2,'GENERAL','Il raffreddamento delle apparecchiature del SMTS viene effettuato con aria raffreddata proveniente da:','Dal pacco SX del gruppo condizionamento velivolo','Dal pacco DX del gruppo condizionamento velivolo','Da entrambi i pacchi','Tutte le risposte sono esatte','B'),(118,2,'GENERAL','Estraendo la SMTS Handle si verifica che:','La Manual Control Valve si chiude e l\'inserto posto all\'interno della \"mixing chamber \" si apre','La Manual Control Valve e l\'inserto posto all\'interno della \"mixing chamber \" si aprono contemporaneamente','La manual Control Valve si apre e l\'inserto si chiude','*******************','C'),(119,2,'GENERAL','Quali sono i valori di tensione nominali in corrente continua ed alternata a 400 Hz applicate ai carichi SMTS:','24/28 VDC; 115 VAC monofase;','28 VDC; 115 VAC monofase; 220/400 VAC trifase','24/28 VDC; 200 VAC monofase; 115/200 VAC trifase','*******************','A'),(120,2,'GENERAL','Quanti inverter sono installati nel Sistema di missione per alimentare le apparecchiature del SMTS','Un inverter monofase e due trifase','Due inverter monofasi e due trifase','Dopo aggiornamento sistema ATOS non ci sono pi?? inverter','Dopo l\'aggiornamento dei sistemi (anno 2020) un solo inverter','D'),(121,2,'FARO','L\'escursione in elevation del faro rispetto al proprio asse ??:','da 0 a -50??','da +5?? a -50??','da 0?? a -60??','*******************','B'),(122,2,'APPARATI RADIO','Quale di queste frequenze ?? quella di guardia del sistema in mod. VHF/AM','121.800 MHZ','121.500 MHZ','128.500 kHZ','*******************','B'),(123,2,'APPARATI RADIO','Al termine della prodecura di test della radio V/UFH AM-FM la luce \"FAIL\" in caso di malfunzione:','Resta accesa','Continua a lampeggiare','Si spegne','*******************','A'),(124,2,'GENERAL','Il ricevitore HF e la sua antenna Tuning Unit si trovano:','Dietro il pannello posteriore del vano cargo posteriore','Nel Rack Apparati','Sotto il pavimento della cabina passeggeri in posizione baricentrica','Dietro alla postazione del Captain','A'),(125,2,'GENERAL','Con il pulsante HF dell\'Audio Control Panel della MOC1 inserito cosa avviene se agisco sullo switch INT/RAD','Predispongo la HF per la trasmissione SATCOMM','Si Trasmette sulla frequenza che il TACCO ha impostato sulla radio.','Si Trasmette sulla frequenza che il CAPTAIN ha impostato sulla radio.','*******************','C'),(126,2,'GENERAL','Se il pulsante VFM1 dell\'Audio Control Panel del Tavolo Tattico ?? inserito cosa accade.','Il tacco Trasmette in caso di emergenza con la radio VHF AM del CM1','Il tacco predispone in caso di emergenza  la radio VHF AM del CM1, per il controllo dell\'operatore della MOC1','Il tacco Trasmette  con la radio VHF della MOC1','Il tacco Trasmette  con la radio U/VHF della MOC1','C'),(127,2,'GENERAL','Se il pulsante VFM2 dell\'Audio Control Panel della MOC2 ?? inserito e successivamente premo  il pulsante VU3 su quali radio trasmetto ?','Nessuna perch?? sul ACP della MOC2 non c\'?? il pulsante VU3 (radio U/VHF solo MOC1)','Possono trasmettere sia con la  VHF della MOC1 sia con la UHF della MOC1','Possono trasmettere sia con la  VHF della MOC2 sia con la UHF della MOC1','Posso Trasmettere con la radio V/UHF del SMTS','D'),(128,2,'EOST','Con quale comando si riposiziona la torretta in posizione di riposo','HOLD','STOW','CAGE','*******************','B'),(129,2,'EOST','Quanti e quali sono le focali che si possono impostare sul sensore EON','TRE (21-75-243)','QUATTRO (600-1200-1900-3200)','TRE (600-1200-3200)','A FOCALE CONTINUA DA 9 A 162','B'),(130,2,'EOST','Quali sono le focali che possiamo usare con il sensore IR dellaWESCAM 20','21-75-243','9-162','600-1200-1900-3200','tutte le risposte sono errate','D'),(131,2,'TACTICAL','Quanti USER MARKER possiamo inserire sulla tactical Situation','10','50','100','*******************','C'),(132,2,'RADAR','Dove ?? ubicato il RTP del Radar Gabbiano ULTS80 ?','Rack Apparati','Sotto il pavimento vicino alla botola ATM','MOC 1','Sotto in pavimento vicino al sedile della MOC1','D'),(133,2,'GENERAL','A cosa serve l\'Auto Parallel Switch ?','A commutare l\' HF da modalit?? Radio a DL','A connettere la Work Station (moc1)  al Mission Computer della Moc1','A connettere le Work Station al Mission Computer.','Ha connettere la stampante alle WorkStation del SMTS','D'),(134,2,'GENERAL','Dove ?? ubicata la Analog Video Switch (AVS)','Rack Apparati','Rack Ausiliario','Una nella Moc1 e una nella  Moc2','Moc1','D'),(135,2,'GENERAL','Dove ?? ubicato il \"Interface Unit\"  (IFU) ?','Moc1','Moc1 - Moc 2 (c\'?? ne sono due una per Moc)','Rack Apparati','*******************','A'),(136,2,'GENERAL','Dove ?? ubicato il Contol Panel del faro di ricerca?','Moc1','Console Comunication','Rack Ausiliario','Observer di dx','B'),(137,2,'APPARATI RADIO','A cosa serve anche se non utilizzabile lo Switching Unit  Control Panel ?','A trasformare i segnali digitali del\' EOST in analogico da inviare al faro di ricerca','Ad interfacciare il SMTS con il radar SLAR','A selezionare le modalit?? di funzionamento delle radio HF e V/UHF (moc1)','Tutte le risposte sono errate','C'),(138,2,'RADAR','Al fine di avere una buona immagine ISAR occorre','Mare grosso e angolo di aspetto perpendicolare alla prua del velivolo','Mare calmo e angolo di aspetto sui 40 ?? rispetto alla prua del velivolo','Mare grosso e angolo di aspetto sui 40?? rispetto al fascio radar.','Le risposte B-C sono esatte','C'),(139,2,'GENERAL','Qual\'?? la funzione del TDO ?','Alimentare il Mission Computer','Alimentare i carichi sensibili alle Power interruption ed ?? collegato alla batteria','Alimentare i carichi sensibili alle Power interruption ed ?? collegato alla batteria di emergenza','Tutte le risposte sono errate','C'),(140,2,'GENERAL','Se va in avaria in GEN 1 del velivolo cosa accade.','Il SMTS rimane acceso perch?? il TDO mantiene il carico per il tempo necessario a spegnere il sistema','Il SMTS in automatico spegne tutti i computer in modo da non danneggiarli','Viene a mancare l\'alimentazione del SMTS','*******************','C'),(141,2,'GENERAL','Il pulsante CNT SMOKE in cabina di pilotaggio se messo in ON','Abilita i 3 rilevatori di fumi in cabina','Abilita i 4 rilevatori di fumi in cabina e apre la Manual Control Valve','Abilita i 4 rilevatori di fumi in cabina e chiude la Manual Control Valve','Tutte le risposte sono errate','D'),(142,2,'GENERAL','Quanti container del tipo omologato per ATR 42 si possono imbarcare in configurazione CARGO','9','8','Nessuno per mancanza di omologazione','*******************','A'),(143,2,'GENERAL','Qual ?? la pubblicazione di Maricogecap di riferimento per il personale E.F.V. della linea ATR 42','AER 103 ED OTT 2019','AER 103 ED SETT 2013','AER 102 ED SETT 2013','**','B'),(144,2,'GENERAL','A bordo del velivolo ATR 42 MP chi ?? il responsabile della condotta del velivolo','Pilota con il grado pi?? alto','Mission Commander','Pilota  la qualifica pi?? elevata a bordo','*','C'),(145,2,'GENERAL','Dove siede a bordo del velivolo ATR 42 il CM1','A destra','A sinistra','Tavolo Tattico','*','B'),(146,2,'GENERAL','Dove siede a bordo del velivolo ATR 42 il CM2','A destra','A sinistra','Tavolo Tattico','*','A'),(147,2,'GENERAL','Quante ore di volo deve effettuare un operatore pronto impiego per mantenere la qualifica','80 annuali','35 per semestre','70 annuali','*','B'),(148,2,'GENERAL','Dopo quanto tempo di inattivit?? un operatore pronto impiego perde la qualifica','1 mese','2 mesi','3 mesi','*','B'),(149,2,'RADAR','La massima scala selezionabile in modalit?? SRV ??','160 Nm','80 Nm','40 Nm','*******************','A'),(150,2,'GENERAL','Quanti paracadutisti Si potrebbero imbarcare sul velivolo ATR 42 MP','27','36','48','*******************','A'),(151,2,'GENERAL','Quanti passeggeri si possono imbarcare al massimo sul velivolo ATR 42 MP in configurazione trasporto passeggeri','42','48','46','***','B'),(152,2,'FARO','Il Faro di ricerca ?? alimentato dalla:','Lo STATIC INV 3 PH','TRU','TDO','********','B'),(153,2,'FARO','L\'energia elettrica necessaria per alimentare la lampada ad elevata intensit?? del faro di ricerca viene prelevata dalla:','28 VDC MAIN BUS 1','28VDC HOT MAIN BATT BUS','115/200 VAC MAIN BUS 1','********','C'),(154,2,'FARO','Gli interruttori a posizione momentanea \"START\", installati sia sulla manual control box che sul pannello di controllo della consolle (COC), hanno la funzione di:','Avviare il sistema faro di ricerca ed i relativi circuiti di controllo','Innescare l\'accensione della lampada del faro','Inizializzare l\'asservimento del faro alla telecamera sulla torretta EOST','********','B'),(155,2,'FARO','La calibrazione del faro di ricarca deve essere effettuata:','Con sistema di missione operativo e prima del primo volo della giornata','Dopo la rimozione/installazione del faro di ricerca e/o della torretta EOST e/o delle scatole di controllo e/o dei rispettivi circuiti di interconnessione','Ad ogni primo volo della giornata dopo il decollo e con sistema di missione gi?? operativo','********','B'),(156,2,'GENERAL','Sulla MOC 1 la spia OVER TEMP MOC#1 del quadretto di comando EDU #1 si accende :','Quando la temperatura dell\'aria in uscita dalla consolle MOC 1  supera i 45 ?? C.','Dopo circa 10 sec. da quando sono state ripristinate le normali condizioni di raffreddamento del sistema SMTS','Quando la temperatura dell\'aria in uscita dalla consolle MOC 1  supera i 55 ?? C.','Le risposte B e C sono esatte','C'),(157,2,'GENERAL','Sul quadretto di comando EDU # 1 installato sulla MOC 1, l\'accensione della spia FAULT sul pulsante COOLING FAN avviene in caso di:','Disagree tra il comando e la posizione reale della OVERBOARD VALVE','Forzatura in posizione di chiusura della OVERBOARD VALVE','Avaria del ventilatore di estrazione dell\'aria o dei circuiti elettrici a lui annessi','********','C'),(158,2,'GENERAL','Con velivolo a terra e sistema SMTS operativo, posizionando l\'interruttore OVBD VALVE su CL ci si predispone per :','Chiudere completamente la OVERBOARD VALVE per trattenere l\'aria estratta dalle consolles e dal rack apparati all\'interno del velivolo','Controllare l\'apertura di questa valvola in modo manuale e quindi parzializzare la luce di scarico dell\'aria verso l\'esterno','Aprire completamente la valvola per scaricare rapidamente a terra tutta l\'aria estratta dal sistema SMTS','********','A'),(159,2,'GENERAL','Sul quadretto di comando EDU # 1 installato sulla MOC 1, l\'accensione della spia SMOKE indica che:','All\'interno della MOC 1 (la consolle prioritaria per l\'operativit?? del sistema SMTS) vi ?? presenza di fumo','Nella zona della cabina passeggeri, dove sono installate le consolles, la presenza di fumo ha attivato gli SMOKE DETECTORS del cielo cabina','Nel condotto di estrazione dell\'aria vi ?? presenza di fumo','********','C'),(160,2,'GENERAL','Lo STATIC INV 1 PH alimenta:','Stampante','Radar','Faro di ricerca','********','A'),(161,2,'GENERAL','L\'alimentazione elettrica dei carichi SMTS viene effettuato tramite dei quadretti di comando cos?? dislocati:','Uno in cabina di pilotaggio sulla consolle laterale Sx ed un altro sul Rack Apparati','Uno sulla MOC 1, uno sulla MOC 2 ed uno sulla COC.','Uno in cabina di pilotaggio sulla consolle laterale Dx ed un altro sulla MOC 1','********','C'),(162,2,'GENERAL','Sui quadretti di comando dell\'alimentazione elettrica del sistema SMTS sono installati due interruttori denominati MASTER SW (2P) e PWR(EDU1) ON/OFF la cui funzione singolarmente ?? di:','Consentire il collegamento/scollegamento dei carichi SMTS in DC','Consentire il collegamento/scollegamento dei carichi SMTS in DC e contemporaneamente mantenere lo stato di carica della batteria che ?? collegata sulla barra di emergenza','Consentire il collegamento/scollegamento dei carichi SMTS solo in AC','Le risposte A e C sono esatte','A'),(163,2,'GENERAL','Gli interruttori MASTER SW e SMTS PWR ON/OFF sono dotati ciascuno di due spie inglobate nel pulsante di comando e denominate rispettivamente SHED ed OFF. L\'indicazione SHED sul pulsante MASTER PWR ON/OFF DEL 2?? P ?? accesa nelle seguenti condizioni:','Quando il pulsante MASTER SW viene selezionato OFF','Quando entrambi gli interruttori vengono selezionati OFF','Quando il pulsante MASTER SW viene selezionato ON ed il pulsante PWR ON/OFF viene selezionato OFF','Tutte le risposte sono errate','C'),(164,2,'APPARATI RADIO','Il Captain pu?? utilizzare la radio HF per contattare la C.O. di Roma','Si Sempre perch?? il control Panel della Radio HF ?? ubicata in cabina di pilotaggio','No perch?? la gestione della RADIO HF ?? di competenza dell\'Operatore di Volo','Si, solo per?? se la spia DL sul miscellaneus Control panel in cabina di pilotaggio non sia accesa.','Si, solo per?? se la spia AVAIL sul miscellaneus Control panel in cabina di pilotaggio  sia spenta.','C'),(165,2,'GENERAL','Dove sono ubicate le scatole nere del velivolo','Coda velivolo non accessibili per sicurezza','Coda velivolo accessibili tramite uno sportelli','Cargo vicino alla batteria in modo da essere sempre alimentati','*','B'),(166,2,'RADAR','Il tasto rapido F4 a cosa serve','Ad inizializzare una traccia radar','A selezionare lo zoom radar','A cambiare la scala','Ad effettuare l\'ON TOP','A'),(167,2,'EOST','Pu?? accadere che la posizione del velivolo che leggiamo sullla situazione tattica sia diversa da quella che leggiamo sul monitor sensori (eost).','No perch?? ?? sepre quella che viene dal FMS e GPS','Si solo s?? va in avaria il GPS','Si','**','C'),(168,2,'GENERAL','A cosa serve il comando rapido F9','Ad inizializzare una traccia radar','A marcare l\'on top','A registrare il video EOST','**','C'),(169,2,'EOST','Lo switch \"VIC\" del Hand Control dell\'Eost serve.','A variare l\'algoritmo del AVT','Premendo verso l\'alto a selezionare il sensore da visionare','a selezionare la modalit?? Filter SPA On/Off','Tutte le risposte sono errate','B'),(170,2,'EOST','A cosa serve il tasto \"Geo Focus\" dell\'Hand Control dell\'Eost','Ad attivare/disattivare Auto focus','Ad attivare e disattivare il laser','A selezioanre i POI','**','A'),(171,2,'GENERAL','Come si attivata ELT - Emergency Locator Trasmitter','A contatto con l\'acqua e con una accellerazione > 1 g','Dal pilota','con accellerazione superiore a 5 g','*','C'),(172,2,'GENERAL','Qual ?? la differenza tra MANTA 1 e MANTA 2','Nessuna sono tutte e 2 dei 400','Nessuna sono tutte e 2 dei 500','il M1 ?? un 400 il M2 ?? un 500','il M1 ?? un 500 il M2 ?? un 400','C'),(173,2,'GENERAL','Il radar SLAR su che velivolo ?? installato','Su tutti i velivoli','Solo su Manta 1','E installato sul Manta 2 e sul Manta 1','E\' installato sul Manta 2 e sul Manta 3','C'),(174,2,'GENERAL','L\'apparato ATM ?? imbarcato sul Manta 3.','vero','E installato sul Manta 2 e sul Manta 1','E\' installato sul Manta 2 e sul Manta 3','****','C'),(175,2,'SATCOMM','Dove ?? ubicato il sistema satellitare SDU 7320','moc1','coc','rack apparati in basso','rack apparati in alto','D'),(176,2,'AIS','Dove ?? ubicato il sistema AIS','MOC1','MOC2','rack apparati in alto','rack apparati in basso','D'),(177,2,'SATCOMM','Dove ?? ubicato High Power Amplifier HPA-7450 del sistema satcomm','moc1','cielo cabina sotto l\'antenna','rack apparati','**','C'),(178,2,'SATCOMM','Come si attiva il telefono satellitare','Quando accendiamo un motore avendo cos?? la DC di un generatore','Quando attiviamo il sistema di missione','Devo selezionare POWER ON nella Vcu del SATCOMM','Devo selezionare la connessione background nella vcu del Satcomm','C'),(179,2,'AIS','Come mi accorgo se arriva un mesaggio AIS','Non posso ricevere messaggi perch?? Maricogeap ha inibito questa funzione','Viene visulaizzato in verde una indicazione di AIS MSG in basso a sinistra vicino al pulsante status','Sul tattico viene mostrato un messaggio \"msg AIS\"','**','B'),(180,2,'AIS','Posso inviare dei brevi messaggi con il sistema AIS verso altre stazioni AIS','Non posso ricevere messaggi perch?? Maricogeap ha inibito questa funzione','Si ma devo attivare la funzione TX ON nella finestra active mode','Si basta selezionare il destinatario e premere il pulsante SEND','*','B'),(181,2,'GENERAL','Dove ?? ubicato lo Switch Gbit','MOC1','Rack Apparati','Rack Ausiliario','**','B'),(182,2,'GENERAL','Dove ?? ubicato il Radar Maintenance Panel','MOC1','Rack Apparati in basso vicino al Ricetrasmettitore','Console Comunication','**','C'),(183,2,'GENERAL','Dove ?? ubicato il Digital Master Control Unit (DMCU)','MOC1','Rack Apparati in basso','Console Comunication','**','C'),(184,2,'GENERAL','Dove ?? ubicata la Video Audio Encoder (VAE)','MOC1','Rack Apparati in basso','onsole Comunication','**','C'),(185,2,'GENERAL','Posso cambiare l\'identificativo della missione \"set id\" se ho attivo lo SLAR','SI','NO','**','**','B'),(186,2,'TACTICAL','Tramite la HCU della wescam 20 l si possono registrare le immagini presentati sul monitor sensori in formato analogico.','NO','Si, premendo il PUSH BUTTON frontale sinistro nero','S??, premendo il PUSH BUTTON frontale destro rosso','*','A'),(187,2,'TACTICAL','Di che colore ?? il piano di volo attivo?','Rosso','Verde','Bianco','*','C'),(188,2,'TACTICAL','Si pu??  modificare un piano di volo attivo?','No','S??, ma dopo averlo acquisito selezionando \"Load Curr\" nel Mission Planing e rinviato al FMS','S??, ma dopo averlo acquisito selezionando \"New\" nel Mission Planing e rinviato al FMS','*','B'),(189,2,'TACTICAL','Il pilota pu?? visualizzare le coordinate del piano di volo impostato dal Sistema di Missione ?','No','S??, solo dopo che l\'operatore ha selezionato la funzione nel Mission Planing TO FMS','S??, solo se  su una delle MOC ?? abilitata la funzione FLAT DISPLAY','*','B'),(190,2,'TACTICAL','Quante sono le modalit?? di presentazione delle mappe di navigazione sulla Situazione Tattica?','2','3','4','*','B'),(191,2,'TACTICAL','In quale modalit?? di presentazione il simbolo del velivolo si muove all interno della Mappa?','North Oriented','Heading Oriented','North Fixed Oriented','*','C'),(192,2,'TACTICAL','Che cosa ?? E/O LOS?','La Slant Range del Radar','IL  punto di intersezione con il terreno del sensore elettroottico','IL Bearing del DF','*','B'),(193,2,'TACTICAL','Quali sono i parametri visualizzati dal Measure Tool ?','Solo il RANGE','Solo il BEARING e il TTG','RANGE E BEARING','*','C'),(194,2,'TACTICAL','Si possono visualizzare i dati caratteristici (lat-Long etc) di un target Radar sulla Situazione Tattica?','no','S??, sempre','S??, solo dopo averlo selezionato','*','C'),(195,2,'TACTICAL','Quali sono i dati che fornisce la funzione di Cursor Reporting ?','La posizione geografica (Lat, Lon) del velivolo','La posizione geografica dei target','La posizione geografica del cursore','*','C'),(196,2,'TACTICAL','Cosa permette di effettuare la funzione SET ID?','di settare i dati del piano di volo','di inserire o modificare un identificativo della missione','di visualizzare la Lat, Long  del coursor Reporting','*','B'),(197,2,'GENERAL','Quando generalmente, in condizioni standard, si procede alla procedura di attivazione del S.M.T.S.','Durante le manovre di rullaggio, in modo di avere il sistema operativo subito dopo il decollo.','dopo l\' after take off check list a descrizione del Captain','Dopo la messa in moto di entrambi i velivoli in modo che possiamo raffreddare il S.M.T.S.','*','B'),(198,2,'GENERAL','Quando generalmente in condizioni standard si procede allo spegnimento del S.M.T.S.','A discrezione del CAPTAIN, prima delle manovre di atterraggio.','Con il velivolo al parcheggio, prima di spegnere il motore dx','Durante le fasi di rullaggio per poter scaricare dal data base i dati di missione','*','A'),(199,2,'GENERAL','In condizioni normali dopo quando tempo la spia fault del pulsante cooling fan si spegna dopo averlo messo in posizione di on.','Essendo una spia di FAULT, dopo aver eliminato l\'avaria.','Dopo circa 2 minuti','Dopo circa 3 minutii','*','B'),(200,2,'TACTICAL','Dalla postazione della MOC 1  si pu?? visionare la quota BAROMETRICA del velivolo','Sulla titolazione delle immagini video dei sensori se abilitati con il pulsante frontale nero dell\'Hand Control','Sulla titolazione della presentazione delle immagini video dei sensori se abilitati con il pulsante frontale rosso dell\'Hand Control','Si pu?? vedere sulla STATUS AREA.','Le risposte A e C sono corrette','C'),(201,2,'TACTICAL','Dalla MOC1 come si pu?? visionare la quota RADAR','Sulla titolazione delle immagini video dei sensori EOST.','Si chiede al CM1-CM2','Si  pu?? visionare nella STATUS AREA','Le risposte  A e C sono corrette','D'),(202,2,'TACTICAL','Supponendo che stiamo volando sul mare a 9,000 ft sulla MOC2 come si pu?? visionare la quota RADAR ALTIMETRICA','Sulla titolazione delle immagini video dei sensori se abilitati con il pulsante frontale nero dell\'Hand Control','La si pu?? vedere sulla STATUS AREA.','Non si puo\' vedere','Le risposte A e C sono corrette','C'),(203,2,'GENERAL','Come si attiva la cooling fan','Premendo il relativo Pulsante sul EDU1 ma con il Pulsante 1 PH INV su ON','Premendo il relativo Pulsante sul EDU1 ma  con il Pulsante Master Power su ON','Premendo il relativo Pulsante in cabina di pilotaggio','*','B'),(204,2,'RADAR','Cosa indica l\'acronimo STS del Radar Gabbiano ULT80','Scan To Scan','Search to scan','Sector to search','*','A'),(205,2,'RADAR','La massima scala selezionabile in modalit?? HSS ??','160 Nm','80 Nm','40 Nm','*','C'),(206,2,'RADAR','La massima scala selzionabile in modalit?? Wethear','320 Nm','160 Nm','40 Nm','*','A'),(207,2,'RADAR','Quali sono i valori di STS selezionabili:','2-4-6-8','1-4-8-16','1-2-4-8','*','B'),(208,2,'GENERAL','Lo slar su quale velivolo  ?? instalalto','Su tutti i velivloli del Corpo','Su Manta 1 e Mata 2','Solo Manta 1','*','B'),(209,2,'GENERAL','Cosa succede quando la Manual Control Valve Handle viene tirata su e rotata in senso orario ?','Si convoglia tutta l\'aria proveniente dal pacco di raffreddamento del motore dx verso il sistema di missione, ma solo se il CM2 HA premuto il pulsante SMTS Master e loperatore ha premuto il pulsante COOLIN FAN su ON','Si convoglia tutta l\'aria proveniente dal pacco di raffreddamento del motore dx verso il sistema di missione','Si convoglia tutta l\'aria proveniente dal pacco di raffreddamento del motore dx verso il sistema di missione se il CM2 ha messo su off il pulsante AIR FLOW','*','C'),(210,2,'GENERAL','Con il velivolo ATR In configurazione trasporto truppe quanti soldati si possono imbarcare','Nessuno perch?? il velivolo ATR 42 MP non ?? certificato per il trasporto truppe','36','27','*','B'),(211,2,'GENERAL','Con il velivolo ATR in configurazione MEDEVAC quante barelle si possono installare a bordo dellATR 42 MP','6 sul lato dx  - 8 sul lato sinistro','6 sul lato dx  - 6 sul lato sinistro','Nessuna Perch?? in sede di certificazione questa configurazione non ?? stata autorizzata','*','A'),(212,2,'EOST','A cosa serve la funzione  AVT ?','Registrare in formato digitale le immagini dei sensori della torretta','Variare i parametri (focus, speed, zoom speed.) del sensore ATV','Ad inseguire un bersaglio automaticamente con la torretta','*','C'),(213,2,'GENERAL','Quali radio si possono controllare  e gestire dalla MOC2','VHF marino, UHF, HF','Solo VHF marino','VHF marino e HF','*','B'),(214,2,'GENERAL','Dalla MOC 1 si possono controllare  e gestire le seguenti Radio','VHF marino e la  V/UHF','Solo VHF marino','V/UHF, HF','*','A'),(215,2,'GENERAL','Quali radio si possono controllare e gestire dalla postazione del Tavolo Tattico ?','V- UHF se non asservita al Data Link','VHF marino e HF  se non asserviti al Data Link','Nessuna','Le risposte A e B sono esatte','C'),(216,2,'APPARATI RADIO','Dalla postazione MOC1 si pu?? ascoltare il canale di Soccorso VHF CH 16 ?','Solo se smista il selettore il selettore di funzionamento  su Guard 1','Solo se smista il selettore il selettore di funzionamento  su Guard 2','Sempre','Le risposte A e B sono esatte perch?? sia G1 che G2 sono impostate sul ch 16','C'),(217,2,'APPARATI RADIO','Dalla postazione MOC2 si pu?? trasmettere in fonia con la U-VHF supponedo che la radio sia regolarmente accesa e con una frequenza impostata ?','Si Selezionando il selettore VFM2 del proprio Audio Control Panel.','Si Selezionando il selettore VU3 del Proprio Audio Control Panel','Si solo Selezionando il selettore VU3 del  Audio Control Panel della MOC1','No mai','B'),(218,2,'APPARATI RADIO','Dalla postazione MOC1 si pu?? trasmettere in fonia in HF supponendo che apparato sia acceso e settato ?','Si Sempre, Selezionando il selettore HF del proprio Audio Control Panel.','Si Selezionando il selettore HF del proprio Audio Control Panel solo con Sistema di Missione ATTIVO','Con Sistema Spento Sempre.  Con il sistema acceso verificando che Indicazione DL sul Swicting Unit non sia accesa','*','C'),(219,2,'APPARATI RADIO','Se la radio VHF marino della MOC1 ?? selezionato su CHARLIE 5 ma il selettore di modo ?? su Guard, dalla postazione del Tavolo Tattico???','Selezionando il pulsante dellAudio Control Panel VU1, si trasmette su charlie 5 e si riceve sul ch16','Selezionando il pulsante dellAudio Control Panel FM1, si trasmette su charlie 5 e si riceve sul ch16','Selezionando il pulsante dellAudio Control Panel VFM1, si trasmette  sul ch16','*','C'),(220,2,'APPARATI RADIO','Se gli apparati radio VHF marino e U/VHF della MOC1 sono in avaria, l\'operatore alla MOC1 puo trasmettere sul canale 16.','No puo solo ricevere selezionando il selettore sullAudio Control Panel VFM2','Si selezionando sul proprio A.C.P. VFM2','No mai','*','B'),(221,2,'GENERAL','Quante sono le uscite di sicurezza del velivolo ATR 42 MP','2 sul lato destro - 1 lato sinistro e 1 cielo cabina pilotaggio','2 sul lato destro - 2 lato sinistro e 1 cielo cabina pilotaggio','1 sul lato destro - 2 lato sinistro e 1 cielo cabina pilotaggio','*******************','B'),(222,2,'GENERAL','Premendo il pulsante VU3 sull\' audio Control Panel della MOC 2, agendo sul selettore RAD   con quale radio trasmettiamo','Nessuna perch?? la MOC 2 non ha il V/UHF','V/UHF della MOC1','V/UHF della MOC2','*******************','B'),(223,2,'GENERAL','L\'apparato ATM su quali velivoli pu?? essere imbarcato ?','Solo Manta 1','Su tutti i velivoli','E installato sul Manta 2 e sul Manta 1','E\' installato sul Manta 2 e sul Manta 3','B'),(224,2,'EOST','Dove ?? ubicata la DMCU','MOC1','MOC2','Console Comunication','**','C'),(225,2,'EOST','A cosa serve lo switch VIC presente sul HCU della torretta Wescam','Aumentare o diminuire lo Zoom','A cambiare la visualizzazione dei sensori','A variare la finestra dell\'AVT','*','B'),(226,2,'EOST','A cosa serve il tasto rapido F11?','A variare in azimuth e in elevation la posizione del EOST','A spostare in maniera automatica la torretta EOST su un User Marker specifico','Al puntamento automatico della torretta EOST su un target','Le risposte B e C sono corrette','D'),(227,2,'GENERAL','Lo Slar su quale velivolo non ?? installato','Solo su Manta 1','Manta 2 e Manta 3','Manta 3','Le risposte a e b sono corrette','C'),(228,2,'EOST','Quanti e quali sono le focali che si possono impostare sul sensore EON/SWIR','TRE (21-75-243)','QUATTRO (600-1200-1900-3200)','TRE (600-1200-3200)','A FOCALE CONTINUA DA 9 A 162','B'),(229,2,'EOST','Quanti e quali sono le focali che si possono impostare sul sensore EOW','TRE (21-75-243)','QUATTRO (600-1200-1900-3200)','TRE (600-1200-3200)','A FOCALE CONTINUA DA 9 A 162','D'),(230,2,'EOST','Dopo l\'attivazione per prendere il controllo della torretta devo:','Premere MAN','Premere FWD e poi MAN','Premere AUTO','*','B'),(231,2,'Tactical','Quanti capture posso inserire per ogni target salvato del Surface Report','1','10','5','*','B'),(232,2,'Tactical','Qual ?? la durata massima che posso registrare di un video del EOST ?','In base alla capienza del HARD DISK','60 minuti','30 minuti','1 Gb','C'),(233,3,'AFCS','THE AIRCRAFT IS PROVIDED WITH AN AUTOMATIC DIGITAL FLIGHT CONTROL SYSTEM (AFCS) AND IT ACHIEVES:','A. Autopilot (AP) and/or yaw damper (YD) functions.','B. Flight director (ED) function.','C. A + B are correct plus altitude alert.','*','C'),(234,3,'AFCS','THE MAIN COMPONENTS OF \"AFCS\" ARE:','A. One computer, one control panel, two advisory display units (ADU), three servo actuators.','B. Two computers FD and AP, one control panel, one ADU, three servo actuators.','C. One computer, one control panel, one ADU, three servo actuators.','*','C'),(235,3,'AFCS','THE ELECTRICAL SUPPLY OF THE MAIN \"AFCS\" COMPONENTS IS:','A. EMER BUS and STBY  BUS','B. ESS BUS for AP off lights and AP disconnect circuit.','C. A + B are correct','*','C'),(236,3,'AFCS','WHICH ARE THE COMMON \"FD\" AND \"AP\" VERTICAL (PITCH) MODES OPERATED BY VERTICAL MODES \"PB\" ?','A. lAS HOLD, VS HOLD, ALT CAPTURE, ALT HOLD.','B. LAS HOLD, VS HOLD, ALT HOLD.','C. lAS HOLD, VS HOLD, ALT HOLD, GO AROUND.','*','B'),(237,3,'AFCS','WHICH ARE THE COMMON \"FD\" AND \"AP\" LATERAL (ROLL) MODES  OPERATED BY LATERAL MODES \"PB\"?','A. HDG SEL, NAV, APP, BC.','B. HDG SEL, NAV, BC.','C. HDG SEL, NAV, APP, GO AROUND.','*','A'),(238,3,'AFCS','WHICH FLIGHT DIRECTOR VERTICAL (PITCH) MODES HAVE AN  \"ARMED\" PHASE?','A. ALT SEL, lAS and VS HOLD.','B. ALT SEL and GS TRACK','C. ALT, IAS and VS HOLD.','*','B'),(239,3,'AFCS','WHICH FLIGHT DIRECTOR LATERAL (ROLL) MODES HAVE AN \"ARMED\"  PHASE?','A. HDG and NAV only.','B. APP and BC only.','C. NAV, APP and BC only.','*','C'),(240,3,'AFCS','FLIGHT DIRECTOR AND AUTOPILOT MODES:','A. The GO AROUND mode is only FD mode not AP.','B. The modes APP and GO AROUND have vertical (pitch) and lateral (roll) modes at the  same time.','C. A + B are correct.','*','C'),(241,3,'AFCS','WHICH \"PB\" MUST BE PUSHED ON THE \"AFCS\" CONTROL PANEL TO INTERCEPT AND TRACK A \"VOR\" RADIAL?','A. APP.','B. NAV.','C. BC.','*','B'),(242,3,'AFCS','IN \"APP\" MODE (LOC AND GS ARM), WHICH \"PB\" MUST BE PUSHED ON  THE \"AFCS\" CONTROL PANEL TO INTERCEPT AND FOLLOW THE \"GS\"?','A. The GS will be captured automatically in any case.','B. The GS will be captured automatically after LOC capture.','C. After LOC capture you have topss APP mode PB again.','*','B'),(243,3,'AFCS','WHAT ALLOWS THE \"BANK\" PUSH-BUTTON ON \"AFCS\" CONTROL PANEL','A. The alternate selections of the bank angle in the HDG SEL or in VOR and LOC capture mode.','B. The alternate selections of HI bank angle limit (27┬░ max) or a low bank limit (15┬░ max) in  the HDG SEL only.','C. The manual control of the bank angle, in the HDG SEL only through the touch control  steering (TCS).','*','B'),(244,3,'AFCS','THE \"ALT\" SELECT MODE IS AUTOMATICALLY ARMED WHEN THE AIRCRAFT CLIMES (OR DESCENDS) TOWARDS THE SELECTED   ALTITUDE','A. This assertion is correct.','B. Incorrect, the ALT SEL mode must be armed then engaged before selecting a new altitude.','C. Incorrect, the STBY mode PB must be pushed to enable the new altitude to be select.','*','A'),(245,3,'AFCS','IF \"ALT\" AND \"GS\" VERTICAL MODE ARE ARMED AT THE SAME TIME,   WHAT HAPPENS?','A. The first one meets capture conditions becomes active.','B. If GS track captures first, it will inhibit the capture of ALT SEL (no ALT alert).','C. If ALT SEL captures first, it will not inhibit the capture and tack phases of GS.','D. A +B + C  are correct.','D'),(246,3,'AFCS','THE USE OF \"lAS\" MODE IS?','A. To climb or descent using a pre-selected VS.','B. To obtain a desired speed in ALT mode.','C. To climb or descent using a selected speed.','*','C'),(247,3,'AFCS','WHEN THE \"AP\" IS ENGAGED WITH NO \"FD\" MODE SELECTED, WHAT HAPPENS?','A. The AP maintains the present pitch attitude (15┬░ max) and the present roll (6┬░ to 35┬░) or the  present heading if the bank angle is below 6┬░.','B. The AP maintains the present vertical speed and the present heading.','C. The AP maintains the present pitch attitude, also wings are leveled, and the heading is maintained.','*','C'),(248,3,'AFCS','WHEN \"AP\" IS ENGAGED WITH AN ACTIVE \"FD\" MODE ENGAGED:','A. The AP follows the FD mode, only if you press the active mode again.','B. The AP follows the FD mode.','C. The AP engages BASIC mode.','*','B'),(249,3,'AFCS','WHEN THE PILOT ACTS ON THE TOUCH CONTROL STEERING (TCS),THIS ALLOWS:','A. To control manually and temporarily the aircraft without disengaging the active FD and/or  AP mode.','B. To control manually and temporarily the aircraft, and return in BASIC mode.','C. To disconnect the AP but maintains YD','*','A'),(250,3,'AFCS','IF BOTH \"AP\" AND \"YD\" ARE \"OFF\", WHICH ACTION IS REQUIRED TO  ENGAGE THE \"AP\"?','A.The YD PB must be pressed first, then press the AP PB','B.The AP PB must be pressed first, then press the YD PB.','C.Press the AP PB.','*','C'),(251,3,'AFCS','IF THE \"AP\" IS \"ON\", WHAT HAPPENS IF THE \"YD\" PB IS PUSHED?','A. Both the AP and YD disengages.','B. The YD only disengages.','C. AP remains engaged in BASIC mode.','*','A'),(252,3,'AFCS','THE \"YD\" FUNCTION IS ACTIVATED AUTOMATICALLY:','A. Anytime the AP is engaged.','B. By  pushing YD PB.','C. A + B are correct.','*','C'),(253,3,'AFCS','WHAT HAPPENS WHEN THE PITCH WHEEL IS ACTUATED WITH THE   \"AP\" ENGAGED IN \"ALT HOLD\" MODE?','A. A new altitude reference is set and will be acquired by the AP.','B. Nothing, it is inhibited in ALT HOLD.','C. The AP disconnects and the pitch wheel can be used only in FD mode for IAS and VS','*','B'),(254,3,'AFCS','IF THE \"AP\" IS \"ON\", WITH THE \"FD\" ENGAGED IN THE \"HDG\" AND \"ALT\" MODE, WHAT HAPPENS IF THE \"HDG\"  \"PB\" IS PRESSED AGAIN ?','A. The vertical bar disappears from the EADI, and the AP returns to BASIC mode on the roll axis only.','B. Nothing.','C. AP disengages','*','A'),(255,3,'AFCS','IF THE \"AP\" IS \"ON\", WITH THE \"FD\" ENGAGED IN THE \"HDG\" AND \"ALT\" MODE, WHAT HAPPENS IF THE \"STBY\" \"PB\" IS PRESSED?','A. The Horizontal and vertical bars disappear from EADI, and the AP disengages.','B. The horizontal and vertical bars disappear from EADI, and the AP returns in BASIC mode  on both axes.','C. The AP remains in the last mode selected without possibility to change.','*','B'),(256,3,'AFCS','MANUAL DISENGAGEMENT OF \"AP\" IS ACHIEVED BY:','A. Quick disconnect PB on the control wheel, or AP PB on AFCS control panel.','B. Action on Pitch TRIM or YD PB on AFCS control panel.','C. GA PB on PL, or pilots force on the pedal over 30daN.','D. A+B+C are correct','D'),(257,3,'AFCS','AUTOMATIC DISCONNECTION OF \"AP\" OCCURS WHEN:','A. The engagement condition of AP or/and YD is no longer met or mismatch between the two  pitch trims.','B. Stall warning indicator threshold is achieved.','C. There is a disagreement between the two AHRS or the two ADC.','D. A+B+C are correct.','D'),(258,3,'AFCS','DURING THE ALTITUDE CAPTURE PHASE, WHAT HAPPENS IF YOU  SELECT A NEW ALTITUDE WITH \"ALT\" KNOB?','A. This new altitude is memorized by the AFCS, but the aircraft maintains the first one.','B. AP will return to BASIC pitch hold mode (vertical mode has to be re-selected).','C. This altitude is not memorized by the AFCS, but the aircraft maintains the first one.','*','B'),(259,3,'AFCS','THE \"AFCS\" DUAL COUPLING:','A. Automatically occurs when both ILS frequencies are selected and LOC/GS track obtained.','B. Must be set by the pilot after APP mode selection and before GS capture.','C. Can be selected when LOC track is effective.','*','A'),(260,3,'AFCS','DURING THE GO AROUND PHASE, ACTION ON EITHER GO AROUND \"PB\"  WILL','A. Disengage AP and FD bars disappear.','B. Disengage AP and the AFCS provides PD commands only to manually acquire and maintain predetermined minimum safe pitch attitude and present Heading.','C. The GA PB when depressed, automatically moves the PL to the required power setting,  but the pilot should manually maintain the speed.','*','B'),(261,3,'AFCS','HOW IS THE GO AROUND MODE CANCELED?','A. By using TCS or by pushing STBY PB.','B. Selecting a new vertical mode or engaging AP.','C. A + B are correct.','*','C'),(262,3,'AFCS','HOW ARE \"ADU\" CAUTIONS MESSAGE CLEARED FROM THE SCREEN?','A. By pushing STBY.','B. By pushing RESET.','C. By pushing R SEL or L SEL (as appropriate).','*','B'),(263,3,'CCAS','THE HEART OF CCAS IS THE \"MFC\" SYSTEM AND THE OPERATING MODULES ARE:','A.      1A and 2B;','B. ┬á┬á┬á 1A and 2A;','C.     1B and 2B;','*','C'),(264,3,'CCAS','THE FOLLOWING WARNINGS ARE NOT PROCESSED BY THE \"MFC\":','A.┬á┬á┬á┬á┬á Engine fire, excess cab. ^ press., excess cab. altitude,           nacelle overheat and smoke;','B.┬á┬á┬á┬á┬á Engine fire, smoke, engine oil low pressure, excess cab.           altitude and pitch disconnect;','C.┬á┬á┬á┬á┬á Engine fire, excess cab ^ press., excess cab. altitude, smoke          and flaps unlock.','*','A'),(265,3,'CCAS','A CENTRALIZED CREW ALERTING SYSTEM (CCAS) IS MONITORING ALL AIRCRAFT SYSTEMS IN ORDER TO PROVIDE THE FOLLOWING FUNCTIONS:','A.┬á┬á┬á┬á┬á Alert the crew of system malfunction (MASTER WARNING or          MASTER CAUTION);','B.┬á┬á┬á┬á┬á Identify the malfunction (CREW ALERTING PANEL  C.A.P);','C.┬á┬á┬á┬á┬á Direct the appropriate actions (LOCAL ALERT).','D.┬á┬á┬á┬á┬á A + B + C are correct.','D'),(266,3,'CCAS','THE MASTER CAUTION SYSTEM IS TYPICALLY IDENTIFIED FOR:','A.┬á┬á┬á┬á┬á Emergency situation;','B.┬á┬á┬á┬á┬á Abnormal situation;','C.┬á┬á┬á┬á┬á Advisories.','d.','B'),(267,3,'CCAS','THE MASTER WARNING SYSTEM IS TYPICALLY IDENTIFIED FOR:','A.┬á┬á┬á┬á┬á Emergency situation;','B.┬á┬á┬á┬á┬á Abnormal situation;','C.┬á┬á┬á┬á┬á Advisories.','*','A'),(268,3,'CCAS','TO EXTINGUISH MASTER WARNING OR MASTER CAUTION ITÔÇÖS NECESSARY:','A.┬á┬á┬á┬á┬á To press the corresponding light;','B.┬á┬á┬á┬á┬á To perform the necessary corrective action;','C.┬á┬á┬á┬á┬á To depress CLR push button on the CAP.','*','A'),(269,3,'CCAS','CAN YOU EXTINGUISH ALL C.A.P. LIGHT BY PRESSING \"CLR\" PUSH BUTTON?','A.┬á┬á┬á┬á┬á Yes;','B.┬á┬á┬á┬á┬á Yes, for the red and amber light except PRK BRK, GPWS       FAULT and MAINT PNL;','C.┬á┬á┬á┬á┬á Yes, for the amber light except PRK BRK, GPWS FAULT and MAINT PNL.','*','C'),(270,3,'CCAS','T.O. CONFIG TEST IS USED BEFORE TAKE OFF:','A.┬á┬á┬á┬á┬á To check if aircraft  configuration is correct by simulating throttles at take off position (except parking brake);','B.┬á┬á┬á┬á┬á To perform an automatic recall;','C.┬á┬á┬á┬á┬á A + B are correct.','*','C'),(271,3,'CCAS','T.O. CONFIG TEST IS USED BEFORE TAKE OFF TO CHECK:','A.┬á┬á┬á┬á┬á PWR MGT selector in TO position (ENG);','B.┬á┬á┬á┬á┬á Pitch trim in green sector and flaps 15┬░ position (CONFIG);','C.┬á┬á┬á┬á┬á Travel limit unit in LO SPD configuration (TLU);','D.┬á┬á┬á┬á┬á A + B + C are correct','D'),(272,3,'CCAS','WHEN PRESSING \"T.O. INHI\" PUSH BUTTON, YOU WILL INHIBIT:','A.┬á┬á┬á┬á┬á All red and amber light on CAP;','B.┬á┬á┬á┬á┬á All amber light on CAP;','C.┬á┬á┬á┬á┬á Eng. Oil low pressure, smoke warning and all the cautions amber light on CAP except EFIS COMP, PRK BRK, GPWS FAULT, MAINT PNL, ENG (for ADC SW fault alert), FLT CTL (for TLU or FLAP ASYM. Alert).','*','C'),(273,3,'CCAS','WHEN IS THE T.O. INHI FUNCTION AUTOMATICALLY CANCELED?','A.┬á┬á┬á┬á┬á As soon as one gear leg is not locked down;','B.┬á┬á┬á┬á┬á Gear is locked up;','C.┬á┬á┬á┬á┬á Gear and flaps are up;','d.┬á┬á┬á┬á┬á The first leg of landing gear and flaps are up','A'),(274,3,'CCAS','MANUAL CANCELLATION OF \"T.O. INHI\" IS OBTAINED:','A.┬á┬á┬á┬á┬á By pressing RCL PB;','B.┬á┬á┬á┬á┬á By pressing CLR PB;','C.┬á┬á┬á┬á┬á By pressing T.O. INHI PB;','d.┬á┬á┬á┬á┬á By selecting PWR MGT on another position than T.O.','A'),(275,3,'CCAS','THE EMERGENCY AUDIO CANCEL SW, ALLOWS THE CREW TO CANCEL A NUISANCE AURAL WARNING, WHICH WILL BE REACTIVATED:','A.┬á┬á┬á┬á┬á At the next aircraft power up only;','B.┬á┬á┬á┬á┬á At the next aircraft power up, or after MFC 1B/2B reset, or after pressing RCL PB or following to CONFIG TEST for all aural warnings;','C.┬á┬á┬á┬á┬á At the next aircraft power up, or after MFC 1B/2B reset, or after pressing RCL PB or following to CONFIG TEST, except for LANDING GEAR, VMO, VFE, VLE, STALL WARNING, PITCH TRIM WHOOLER, AP DISCONNECT, witch will be rearmed as soon as the triggerin','*','C'),(276,3,'CCAS','PUSHING AN ILLUMINATED RED MASTER WARNING LIGHT WILL CANCEL WHICH OF THE FOLLOWING?','A.┬á┬á┬á┬á┬á Any warning or caution light illuminated at that time;','B.┬á┬á┬á┬á┬á Any warnings light illuminated at that time;','C.┬á┬á┬á┬á┬á The MASTER WARNING light and CAP (crew alerting panel) red light illuminated at that time;','D.┬á┬á┬á┬á┬á Only the MASTER WARNING light and the associated aural warning','D'),(277,3,'CCAS','ALL THE INHIBITED OR CANCELED \"CAUTION\" LIGHT ON CAP CAN BE RECALLED BY DEPRESSING:','A.┬á┬á┬á┬á┬á RCL PB;','B.┬á┬á┬á┬á┬á CLR PB;','C.┬á┬á┬á┬á┬á TO INHI PB.','*','A'),(278,3,'CCAS','WHICH RED CREW ALERT PANEL LIGHT CAN BE CLEARED BY USING THE CLR BUTTON?','A.┬á┬á┬á┬á┬á None;','B.┬á┬á┬á┬á┬á All of them;','C.┬á┬á┬á┬á┬á All except SMOKE and FIRE light.','*','A'),(279,3,'CCAS','THE A/C STALL WARNING PROTECTION TRIGGERS:','A.┬á┬á┬á┬á┬á Aural alert (cricket) plus shaker activation;','B.┬á┬á┬á┬á┬á Stick pusher activation;','C.┬á┬á┬á┬á┬á A + B are correct.','*','C'),(280,3,'CCAS','STALL ALERT AND STICK PUSHER ACTIVATION IS GENERATED BY:','A.┬á┬á┬á┬á┬á Critical angle of attack information, directly processed by CCAS;','B.┬á┬á┬á┬á┬á Critical speed information;','C.┬á┬á┬á┬á┬á A + B are correct.','*','A'),(281,3,'CCAS','STICK PUSHER ACTIVATION IS INHIBITED:','A.┬á┬á┬á┬á┬á On ground and as long as T.O. INHI is on;','B.┬á┬á┬á┬á┬á On ground and as long as flaps are not retracted;','C.┬á┬á┬á┬á┬á On ground and for 10 seconds after lift off and in flight when the aircraft descends below 500 ft RA.','*','C'),(282,3,'CCAS','ICING \"AOA\" ILLUMINATED, THE STALL ALERT THRESHOLD IS AT A CRITICAL ANGLE OF ATTACK OF:','A.┬á┬á┬á┬á┬á 8┬░ always;','B.┬á┬á┬á┬á┬á Lower than normal, depending on flaps position;','C.┬á┬á┬á┬á┬á 7.6┬░. for take off and change when 10 minutes have elapsed after lift-off, or when flaps are retracted to 0┬░, whichever occurs first;','D.┬á┬á┬á┬á┬á B + C are correct.','D'),(283,3,'CCAS','STICK PUSHER ACTIVATION OCCURS:','A.┬á┬á┬á┬á┬á Before stall warning advise;','B.┬á┬á┬á┬á┬á After stall warning advise;','C.┬á┬á┬á┬á┬á At the same time of stall warning advise.','*','B'),(284,3,'CCAS','WHENEVER ICING \"AOA\" IS ILLUMINATED, THE A/C IS PROTECTED BY AN EARLIER STALL THRESHOLD AS FOLLOW:','A.┬á┬á┬á┬á┬á Stall alert threshold is modified for flaps 0┬░ only;','B.┬á┬á┬á┬á┬á Stall alert threshold is modified but not stick pusher threshold;','C.┬á┬á┬á┬á┬á Stall alert threshold and stick pusher threshold are modified;','D.┬á┬á┬á┬á┬á Only stick pusher threshold is modified.','C'),(285,3,'CCAS','IN CASE OF \"MFC 1B\" AND \"MFC 2B\" FAILURE:','A.┬á┬á┬á┬á┬á All level two (CAUTION) alerts are processed without MASTER CAUTION;','B.┬á┬á┬á┬á┬á All CCAS operations continue;','C.┬á┬á┬á┬á┬á All level three (WARNING) alerts, except CONFIG, ENG OIL, PROP BRK, are processed without MASTER WARNING and CRC, all level two alert (CAUTION) are not processed.','*','C'),(286,3,'CCAS','STICK PUSHER SHAKER TEST HAS TO BE PERFORMED:','A.┬á┬á┬á┬á┬á Before each flight;','B.┬á┬á┬á┬á┬á Daily;','C.┬á┬á┬á┬á┬á Once a week;','D.   Every 200 hours.','B'),(287,3,'CONDITIONING','PACK VALVES FUNCTIONS ARE:','A. Air pressure control only.','B. Shut off, pressure control and hence flow control.','C. Shut off, flow control, and temperature control.','*','B'),(288,3,'CONDITIONING','PACKS PUSH-BUTTON \"ON\", MEANS THAT:','A. Pack valveis fully opening all the cases.','B. Pack valve is opened if the opening conditions are met or encountered.','C. Pack valve regulates pressure and airflow in all the cases.','*','B'),(289,3,'CONDITIONING','AIR CONDITIONING PACKS ARE INSTALLED:','A. Both in the left landing gear fairing.','B. Both in the RH landing gear fairing.','C. One in each landing gear fairing.','*','C'),(290,3,'CONDITIONING','WHICH PACK IS THE PRIMARY SUPPLIER OF COCKPIT AIR?','A. Left.','B. Right.','C. There is no priority.','*','A'),(291,3,'CONDITIONING','WHAT HAPPENS TO EXCESS AIR FROM THE LEFT PACK?','A. It is vented overboard.','B. It is used to supply the cabin.','C. It is used for cargo ventilation.','*','B'),(292,3,'CONDITIONING','WHAT IS THE ELECTRICAL POWER SUPPLY FOR TEE PACKS?','A. DC ESS BUS.','B. DC BUS 1 and 2.','C. ACW BUS 1 and 2.','*','A'),(293,3,'CONDITIONING','PACK VALVES ARE.','A. Electrically operated and electrically controlled.','B. Pneumatically operated and pneumatically controlled.','C. Pneumatically operated and electrically controlled.','*','C'),(294,3,'CONDITIONING','AIR FLOW LEVEL IS CONTROLLED:','A. Automatically, according to the bleed air pressure.','B. Manually, by a single NORMAL HIGH push-button.','C. A + B are correct.','*','C'),(295,3,'CONDITIONING','THE SELECTION OF AIRFLOW \"NORMAL /HIGH\" FROM PACKS IS:','A. Automatic, depending of PL position.','B. Automatic, depending of cabin air temperature.','C. Manual, in any case.','*','C'),(296,3,'CONDITIONING','WHAT HAPPENS WHEN THE \"PACK FLOW\" PUSH-BUTTON IS \"IN\",  \"HIGH\" ILLUMINATES?','A. The recirculation fans start (if the PB are depressed).','B. The recirculation fans continue to run, but at higher speed.','C. Both pack valves are controlled to allow a higher regulated pressure(30 instead of 22 PSI).','*','C'),(297,3,'CONDITIONING','PROVIDED THAT THE Relative PACK VALVES ARE NOT CLOSED, THE  COOLING FANS ARE RUNNING:','A. Automatically, on ground.','B. Automatically, in flight speed below 15OKts and landing gear is retracted for less than 10  minutes.','C. A + B are correct.','*','C'),(298,3,'CONDITIONING','THE COMPT TEMPERATURE SELECTOR:','A. When in manual, the TEMP CTL VALVE is directly controlled by the COMP TEMP  SELECTOR.','B. When in auto, the TEMP CTL VALVE is controlled by the COMP TEMP SELECTOR   through the ELECTRONIC TEMP CONTROLLER.','C. A+B are correct.','*','C'),(299,3,'CONDITIONING','WITH THE TEMP SEL PUSH-BUTTON IN AUTO,THE ELECTRONIC TEMPERATURE CONTROLLER COMPUTES TEMPERATURE CONTROL VALVE POSITION TAKING IN TO ACCOUNT','A. Zone temperature demand only. (COMP TEMP SELECTOR position).','B. Duct outlet temperature and associated compartment temperature only.','C. Both of the above plus A/C skin temperature.','*','C'),(300,3,'CONDITIONING','THE COMPT TEMPERATURE SELECTOR IS OPERATIVE:','A. In automatic mode.','B. In manual mode.','C. in both cases.','*','C'),(301,3,'CONDITIONING','TEMP SELECTOR PB IN MANUAL MODE:','A. Overheat alarm is inhibited.','B. Overheat alarm is not inhibited.','C. Overheat alarm depends on temperature control selector position.','*','B'),(302,3,'CONDITIONING','THE \"COMPT TEMP\" INDICATOR DISPLAYS:','A. Only the compartment temperature of the selected side.','B. The pack and duct temperatures of the selected side.','C. The compartment and duct temperatures of the selected side.','*','C'),(303,3,'CONDITIONING','THE RECIRCULATION FANS:','A. Are used to improve cooling of heat exchanger on the ground.','B. Are used to increase pack valve airflow when in HIGH MODE.','C. Are used to recirculate a part of the cabin air, to increase fresh air supply','*','C'),(304,3,'CONDITIONING','ON GROUND, THE AIR SUPPLIED TO THE AIR CONDITIONING SYSTEM MAY COME FROM:','A. Engines only.','B. Right engine in HOTEL MODE only.','C. Engines or a ground conditioning unit.','*','C'),(305,3,'CONDITIONING','PACK VALVE FAULT MEANS:','A. Actual valve position disagree with the selected position.','B. Overheat downstream of the compressor (T+204┬░C \\393┬░F).','C. A + B are correct.','*','C'),(306,3,'CONDITIONING','IF A PACK VALVE IS CLOSED OR INOPERATIVE:','A. Hot air is still available from that pack via the TEMP CONTROL VALVE.','B. The other pack supplies both compartments (cockpit, cabin) through the mixing chamber.','C. The other pack supplies both compartments via PNEUMATIC CROSSFEED.','*','B'),(307,3,'CONDITIONING','WHEN THE BLEED VALVES ARE SELECTED \"ON\" PACK VALVE PB  PRESSED IN:','A. Both pack valves open immediately','B. Pack 1 valve opens immediately, pack 2 valve opens after 6 sec. delay.','C. Both pack valves open after 10 sec  delay.','*','B'),(308,3,'CONDITIONING','IF THE RELATED ELECTRICAL SUPPLY (OR AIRFLOW) IS LOST,  PACK VALVES','A. Remain in the last position.','B. Are spring-loaded closed.','C. Go in full open position.','*','B'),(309,3,'CONDITIONING','IN CASE OF PACK OVERHEAT DOWNSTREAM OF THE COMPRESSOR:','A. The pack valve on the faulty side closes.','B. Both pack valves close.','C. No pack valve closes.','*','A'),(310,3,'CONDITIONING','IN CASE OF DUCT OVERHEAT DOWNSTREAM OF THE MIXING CHAMBER:','A. The pack valve on the faulty side closes.','B. Both pack valves close.','C. No pack valve closes.','*','C'),(311,3,'CONDITIONING','TEMP SELECTOR OVHT CAUTION IS TRIGGERED WHEN:','A. Duct temperature exceeds 92┬░C.','B. Cabin   temperature exceeds 35┬░C.','C. Compressor temperature exceeds 204┬░C.','*','A'),(312,3,'CONDITIONING','WHAT IS THE MEANING OF A RECIRCUILATION FAN \"FAULT\" LIGHT?','A. Fan RPM too low only.','B. Fan motor overheat only.','C. A + B are correct.','*','C'),(313,3,'CONTROLS','IN FLIGHT ROLL CONTROL IS ACHIEVED BY:','A. Two ailerons.','B. Two ailerons each one with a servo tab.','C. Two ailerons each one with a servo tab and two spoilers.','*','C'),(314,3,'CONTROLS','ROLL CONTROL OPERATION IS ACHIEVED BY ACTUATING:','A. Mechanically the ailerons and hydraulically the spoilers.','B. Mechanically the spoilers and hydraulically the ailerons.','C. Mechanically the ailerons and the spoilers.','*','A'),(315,3,'CONTROLS','ROLL TRIM CONTROL IS PERFORMED USING:','A. Only right aileron tab.','B. Only left aileron tab.','C. Both left and right aileron tabs.','*','B'),(316,3,'CONTROLS','\"SPLR\" LIGHTS Illuminate TO INDICATE:','A. Associated spoiler has failed.','B. Associated spoiler is in the retracted position.','C. Associated spoiler is not in the retracted position.','*','C'),(317,3,'CONTROLS','EACH OF THE TWO ROLL SPOILERS HAS AN HYDRAULIC ACTUATOR WHICH IS CONTROLLED:','A. Mechanically, directly by the related aileron linkage.','B. Mechanically, by control of aileron deflection through the SBV.','C. Electrically, by control of WHEEL position.','*','B'),(318,3,'CONTROLS','AIRCRAFT EQUIPPED WITH SPRING TAB:','A. a spring tab provides a flexible compensation in the left aileron only','B.  a spring tab provides a flexible compensation, which automatically increase with the aerodynamic load on the aileron.','C.  a spring tab provides a fixed compensation on the aileron.','*','B'),(319,3,'CONTROLS','AIRCRAFT EQUIPPED WITH ELECTROMECHANICAL LOCKING DEVICE:','A. Each aileron is immobilized by an electromechanical locking device.','B. Each locking device is electrically actuated through switches installed on the gust lock lever.','C. An AlL LOCK light, installed on the pedestal, will illuminate with CCAS activation whenever one of the locking actuators is in disagreement with the gust lock lever position.','D. A+B+C are correct.','D'),(320,3,'CONTROLS','SPOILERS START TO MOVE AFTER A GIVEN AILERON DEFLECTION (2.5┬░):','A. At low speeds (after landing gear extension).','B. At low speeds (flaps fully extended).','C. At all speeds.','*','C'),(321,3,'CONTROLS','PITCH CONTROL IS ACHIEVED BY:','A. Two hydraulic elevators.','B. Two mechanical drive elevators, each fitted with an automatic tab.','C. One mechanical drive elevator.','*','B'),(322,3,'CONTROLS','PITCH TRIM IS OBTAINED BY:','A. Off setting both automatic tab neutral position.','B. Off setting left automatic tab neutral position.','C. Off setting right automatic tab neutral position.','*','A'),(323,3,'CONTROLS','PITCH TRIM ACTUATION:','A. Both, NORMAL TRIM (control column) and STBY TRIM (pedestal) disconnect AUTO PILOT if engaged.','B. Simultaneous action on NORMAL TRIM and STBY TRIM is not recommended.','C. A+B are correct.','*','C'),(324,3,'CONTROLS','IF ONE CONTROL COLUMN IS JAMMED:','A. Pitch uncoupling procedure allows the other channel to operate one elevator.','B. Pitch uncoupling procedure allows the other Channel to operate the two elevators.','C. An automatic pitch uncoupling allows the other channel to operate the two elevators.','*','A'),(325,3,'CONTROLS','AN AURAL \"WHOOLER\" ALERT IS GENERATED BY \"CCAS\" IN CASE OF:','A. Pitch trim use for more then 1 second.','B. 1┬░ movement on pitch trim indicator.','C. 1┬░ movement on yaw trim position indicator.','*','A'),(326,3,'CONTROLS','IN THE YAW AXIS, PILOTS INPUTS ACT DIRECTLY ON THE:','A. Rudder.','B. Rudder tab and through a spring on the rudder itself.','C. Rudder via an HYDRAULIC ACTUATOR.','*','B'),(327,3,'CONTROLS','YAW SPRING TAB FUNCTION REDUCES PILOTS EFFORT ON THE PEDAL:','A. At high speed only.','B. When airload is present on rudder surface.','C. At low speed only.','*','B'),(328,3,'CONTROLS','THE RELEASABLE \"CENTERING UNIT\" (RCU), LOCATED BETWEEN THE RUDDER AND THE LINKAGE TO THE PILOTS PEDALS:','A. Enables a stabilization of the rudder position, when no action is applied on the pedals.','B. As soon as the yaw trim is moved, disengages to allow trim setting.','C. A + B are correct.','*','C'),(329,3,'CONTROLS','THE YAW TRIM IS ACTUATED BY:','A. An electrical trim actuator, shifting the trim tab zero position.','B. An hydraulic trim actuator, shifting the rudder zero position.','C. An electrical trim actuator, shifting the rudder zero position.','*','A'),(330,3,'CONTROLS','THE YAW TRIM POSITION INDICATOR SHOWS:','A. Units of trim motor displacement from neutral.','B. Rudder position.','C. Tab position.','*','A'),(331,3,'CONTROLS','THE TRAVEL LIMITATION UNIT (TLU) IS CONTROLLED BY \"MFC\" MODULES 1A AND 2A THROUGH ADC 1-2 INFORMATIONS AND:','A. Limits pedals stroke and rudder clearance (unlimited until 195 Kt in acceleration, limited until 190 Kt in deceleration).','B. Can by controlled manually in case of MFC 1A and 2A or two ADC failure.','C. A + B are correct.','*','C'),(332,3,'CONTROLS','\"LO SPD\" LIGHT ASSOCIATED TO \"TLU\":','A Illuminates green when rudder travel is not limited.','B illuminates amber when rudder travel is not limited.','C illuminates green when rudder travel is limited.','*','A'),(333,3,'CONTROLS','THE GUST LOCK SYSTEM ACTS ON:','A. Roll control, pitch control and rudder control.','B. Roll control and pitch control.','C. Roll control and rudder control.','*','B'),(334,3,'CONTROLS','HOW IS THE RUDDER PROTECTED, ON GROUND, FOR EXCESSIVE MOVEMENT GENERATED BY GUST?','A. No protection is necessary.','B. By an hydraulic damper.','C. By the TLU.','*','B'),(335,3,'CONTROLS','STICK SHAKER ADVICE IS ACTIVATED BY:','A. One STICK SHAKER ACTUATOR, attached directly on F/O  control column.','B. One STICK SHAKER ACTUATOR, attached directly on CPT control column.','C. Two STICK SHAKER ACTUATORS, each one attached directly on F/O and CPT control columns.','*','C'),(336,3,'CONTROLS','THE STICK PUSHER ACTUATOR IS ATTACHED TO THE LINKAGE OF:','A. CPT control column.','B. F/O control column.','C. CPT and F/O control columns.','*','A'),(337,3,'CONTROLS','THE FLAPS ARE CONTROLLED BY ACTUATORS POWERED BY THE BLUE HYD SYSTEM, HOW IS THE FLAP HYD VALVE BLOCK CONTROLLED?','A. Electrically by DC STBY BUS.','B. Mechanically.','C. Electrical by DC BUS 1.','*','A'),(338,3,'CONTROLS','WHAT IS THE MEANING OF THE BLUE \"EXT\" FLAG ON THE FLAPS POSITION INDICATOR?','A.. flap valve is hydraulically commanding flaps extension.','B. With flaps extended, it indicates a hydraulic leak.','C. A + B are correct.','*','C'),(339,3,'CONTROLS','THE FLAPS ARE PROTECTED BY \"MFC\" IN THE WAY THAT:','A. Clacker alert operates at +180 Kt flaps 15┬░,+160 Kt flaps 25┬░, +150 Kt flaps 35┬░','B. Clacker alert operates at +180 Kt flaps 15┬░,+160 Kt flaps 25┬░, +155 Kt flaps 35┬░','C.  Clacker alert operates at +180 Kt flaps 15┬░,+165 Kt flaps 25┬░, +155 Kt flaps 35┬░','*','A'),(340,3,'CONTROLS','IN ADDITION OF \"CCAS\" ACTIVATION, IF FLAPS ASYMMETRY (6,7┬░) IS DETECTED BY THE \"MFC\":','A. Electrical power to the flap control system is isolated and flaps are locked in position.','B. flaps control lever has no control on the system.','C. A + B are correct','*','C'),(341,3,'CONTROLS','FLAPS UNLK RED LIGHT ON \"CAP\" AND CCAS ALERT IS TRIGGERED WHENEVER:','A. flaps retract untimely more than l0┬░ when flaps are selected at 15┬░ or more.','B. flaps retract untimely more than 3┬░ when flaps are selected at 15┬░ or more.','C. flaps retract untimely more than 10┬░  when flaps are selected at 30┬░.','*','B'),(342,3,'ELECTRICAL','THE DC GND HDLG XFR BUS CAN BE POWERED BY:','A.┬á┬á┬á┬á┬á HOT MAIN BAT BUS on the ground only (with battery switch ON or even OFF, if certain doors or panel are open);','B.┬á┬á┬á┬á┬á HOT MAIN BAT BUS on the ground or in flight (with battery switch ON or even OFF, if certain doors or panel are open);','C.┬á┬á┬á┬á┬á External power;','D.┬á┬á┬á┬á┬á A and C are correct.','D'),(343,3,'ELECTRICAL','BAT SW SELECTOR OFF, NO ENGINE RUNNING, MEANS THAT:','A.┬á┬á┬á┬á┬á Batteries are isolated from their respective HOT BAT BUSSES;','B.┬á┬á┬á┬á┬á DC ESS BUS, DC STBY BUS, INV 1 and AC STBY BUS are isolated from the HOT MAIN BAT BUS;','C.┬á┬á┬á┬á┬á DC EMER BUS is isolated from the HOT EMER BAT BUS;','D.┬á┬á┬á┬á┬á B and C are correct.','D'),(344,3,'ELECTRICAL','NO EXTERNAL POWER, NO ENGINE RUNNING, AND BAT SW OFF, WHICH ITEMS DOES THE DC GND HDLG XFR BUS POWER:','A.┬á┬á┬á┬á┬á Refuel and defuel system, cargo door and cockpit/cabin entrance lighting (2 minutes when sected with the main door open);','B.┬á┬á┬á┬á┬á The DC auxiliary hydraulic pump, via pedestal push button;','C.┬á┬á┬á┬á┬á A + B are correct.','*','C'),(345,3,'ELECTRICAL','BAT SW SELECTED ON, NO ENGINE RUNNING, ALLOWS:','A)┬á┬á┬á┬á┬á The complete DC and ACW systems supply for ground operation;','B)┬á┬á┬á┬á┬á Only the complete DC system supply for ground operation;','C)┬á┬á┬á┬á┬á EXT PWR operation, or a reduced DC supply for a quick Preliminary Cockpit Preparation in order to start the right engine in HOTEL MODE.','*','C'),(346,3,'ELECTRICAL','THE NORMAL VOLTAGE READING FOR A BATTERY IS:','A.┬á┬á┬á┬á┬á For a battery without load 25-28 Volt;','B.┬á┬á┬á┬á┬á For a battery under load 23-28 Volt;','C.┬á┬á┬á┬á┬á 115 V (+/- 4V);','D.┬á┬á┬á┬á┬á A and B are correct.','D'),(347,3,'ELECTRICAL','WHAT ARE THE CAPACITIES OF THE BATTERIES?','A.┬á┬á┬á┬á┬á MAIN BAT 24 V / 43 Ah, EMER BAT 24 V / 15 Ah;','B.┬á┬á┬á┬á┬á MAIN BAT 28.5 V / 43 Ah, EMER BAT 28.5 V / 15 Ah;','C.┬á┬á┬á┬á┬á Both batteries 24 V / 43 Ah.','*','A'),(348,3,'ELECTRICAL','A/C ON GROUND EXT PWR LIGHT AVAIL ILLUMINATED, TO POWER THE DC DISTRIBUTION SYSTEM YOU MUST:','A.┬á┬á┬á┬á┬á Press the EXT PWR SW/LT;','B.┬á┬á┬á┬á┬á Reset the DC GEN 1 and DC GEN 2;','C.┬á┬á┬á┬á┬á Place BAT SW selector ON and press the EXT PWR PB.','*','C'),(349,3,'ELECTRICAL','THE DC SVCE BUS CAN BE POWERED BY?','A.┬á┬á┬á┬á┬á Battery only by pressing the DC SVCE UTLY BUS push-button in the cockpit and on the cabin attendant panel;','B.┬á┬á┬á┬á┬á DC EXT PWR, only the DC SVCE push-button on the cabin attendant panel has control, even with BAT SW OFF;','C.┬á┬á┬á┬á┬á DC BUS 1 if the DC SVCE/UTLY bus push-button in the cockpit and on the cabin attendant panel are ON.','D.┬á┬á┬á┬á┬á B and C are correct.','D'),(350,3,'ELECTRICAL','HOW MANY BUS TIE CONTACTORS (BTC) AND BUS TIE RELAY (BTR) ARE CONTROLLED BY THE MAIN ELECT PWR PANEL BTC PUSH-BUTTON?','A.┬á┬á┬á┬á┬á One between DC BUS 1 and DC BUS 2;','B.┬á┬á┬á┬á┬á One between AC BUS 1 and AC BUS 2;','C.┬á┬á┬á┬á┬á Two, one between DC BUS 1 and DC BUS 2; one between AC BUS 1 and AC BUS 2.','*','C'),(351,3,'ELECTRICAL','A/C ON GROUND, DC EXT PWR ON, DC BTC ON \"ISOL\":','A.┬á┬á┬á┬á┬á DC BUS 1 and DC BUS 2 are isolated;','B.┬á┬á┬á┬á┬á DC BUS 2 and AC BUS 2 are isolated;','C.┬á┬á┬á┬á┬á Batteries are isolated from their DC ESS/DC EMER BUS.','*','B'),(352,3,'ELECTRICAL','WHEN DC GENERATOR IS FUNCTIONING AS A STARTER DURING A BATTERY START:','A.┬á┬á┬á┬á┬á It is electrically supplied by the HOT MAIN BAT BUS and controlled from the DC ESS BUS;','B.┬á┬á┬á┬á┬á It is electrically supplied from the DC EMER BUS by the HOT EMER BAT BUS;','C.┬á┬á┬á┬á┬á It is electrically supplied from the DC BUS 1 or DC BUS 2.','*','A'),(353,3,'ELECTRICAL','WHAT IS THE FUNCTION OF THE EMER BAT WHILE THE ENG START ROTARY SELECTOR IS SET TO START OR CRANK?','A.┬á┬á┬á┬á┬á During a battery start only, it provides backup starter power if the MAIN BAT is weak;','B.┬á┬á┬á┬á┬á During a battery start or when using the opposite GEN for a cross-start (on ground only), it provides backup starter power if the MAIN BAT is weak;','C.┬á┬á┬á┬á┬á It provides positive power to protect critical items from power transient. It never powers the starters.','*','C'),(354,3,'ELECTRICAL','ONCE THE STARTER GENERATOR HAS STARTED THE ENGINE, IT OPERATES IN THE GENERATOR MODE WHEN PASSING:','A.┬á┬á┬á┬á┬á NH 35%;','B.┬á┬á┬á┬á┬á NH 61.5%;','C.┬á┬á┬á┬á┬á NH 70%.','*','B'),(355,3,'ELECTRICAL','WHAT IS THE NOMINAL VOLTAGE OF THE DC GENERATORS?','A.┬á┬á┬á┬á┬á 115 Volts;','B.┬á┬á┬á┬á┬á 26 Volts;','C.┬á┬á┬á┬á┬á 30 Volts.','*','C'),(356,3,'ELECTRICAL','A/C ON GROUND, ENGINE RUNNING, DC EXT PWR AVAILABLE AND ON LINE:','A.┬á┬á┬á┬á┬á DC EXT PWR has no priority over ENG DC GEN;','B.┬á┬á┬á┬á┬á DC EXT PWR has priority over ENG DC GEN;','C.┬á┬á┬á┬á┬á The first on line has priority.','*','B'),(357,3,'ELECTRICAL','ASSUMING NORMAL OPERATION IN FLIGHT, HOW IS THE CONSTANT AC PWR FREQUENCY OBTAINED:','A)┬á From each ACW GEN;','B)┬á From DC busses thought two inverters;','C)┬á Directly from the batteries.','*','B'),(358,3,'ELECTRICAL','ASSUMING NORMAL OPERATION IN FLIGHT, WHEN ARE THE HOT EMER BUS AND HOT MAIN BAT BUS CONNECTED TO THEIR RESPECTIVE BATTERIES?','A.┬á┬á┬á┬á┬á Always;','B.┬á┬á┬á┬á┬á Only in case of both DC GEN failure;','C.┬á┬á┬á┬á┬á Never.','*','A'),(359,3,'ELECTRICAL','ASSUMING NORMAL OPERATION IN FLIGHT, WHEN ARE THE DC EMER BUS AND DC ESS BUS CONNECTED TO THE DC BUS 1 AND/OR DC BUS 2?','A.┬á┬á┬á┬á┬á Always directly;','B.┬á┬á┬á┬á┬á Only when the respective battery needs charging;','C.┬á┬á┬á┬á┬á Always through BAT CHG and its respective HOT EMER or HOT MAIN BAT BUS.','*','C'),(360,3,'ELECTRICAL','INVERTER 1 NORMALLY SUPPLIES?','A.┬á┬á┬á┬á┬á AC BUS 1 only;','B.┬á┬á┬á┬á┬á AC BUS 1 and AC STBY BUS;','C.┬á┬á┬á┬á┬á AC BUS 1 and AC BUS 2 in the event of both DC BUS power lost.','*','B'),(361,3,'ELECTRICAL','DC SVCE AND UTILITY BUS SHED AMBER LIGHT COMES ON WHEN:','A.┬á┬á┬á┬á┬á UTILITY BUS 1 and UTILITY BUS 2 are shed;','B.┬á┬á┬á┬á┬á At least one UTILITY BUS is disconnected from associated main DC BUS;','C.┬á┬á┬á┬á┬á The corresponding DC SVCE and UTILITY BUS push button is switched off.','*','B'),(362,3,'ELECTRICAL','THE EMER BAT CHG FAULT LIGHT COMES ON WHEN:','A.┬á┬á┬á┬á┬á Battery overheat, detected by MFC (automatic disconnection);','B.┬á┬á┬á┬á┬á A failure of the charge contactor;','C.┬á┬á┬á┬á┬á A + B are correct.','*','C'),(363,3,'ELECTRICAL','FOLLOWING AN INVERTER FAILURE, \"INV\" LIGHT ILLUMINATED:','A)┬á Associated AC BUS is lost;','B)┬á Associated AC BUS is supplied through the AC STBY BUS;','C)┬á Associated AC BUS is supplied through the AC BTR by the other INVERTER.','*','C'),(364,3,'ELECTRICAL','IN CASE OF MAIN BAT OVHT WITH MAIN BAT CHG FAULT LIGHT ON, WHAT HAPPENS TO THE BUSSES POWERED BY THAT BATTERY?','A.┬á┬á┬á┬á┬á The HOT MAIN BAT BUS is lost and DC ESS BAT BUS is powered by DC BUS 1;','B.┬á┬á┬á┬á┬á They automatically transfer to EMER BAT;','C.┬á┬á┬á┬á┬á They will loose power when the battery goes below 19.5V.','*','A'),(365,3,'ELECTRICAL','IN FLIGHT WITH ONE ENGINE OPERATING, WHICH INDICATION WOULD BE DISPLAYED ON THE SHUTDOWN ENGINEÔÇÖS DC GEN PUSH-BUTTON?','A.┬á┬á┬á┬á┬á White OFF if PB is released;','B.┬á┬á┬á┬á┬á White OFF if PB is depressed (IN);','C.┬á┬á┬á┬á┬á Amber FAULT if PB is depressed (IN);','D.┬á┬á┬á┬á┬á A and C are correct.','D'),(366,3,'ELECTRICAL','ENGINE RESTART WITH THE DC GEN PUSH-BUTTON IN (DEPRESSED), WHAT SHOULD HAPPEN TO THE PUSH-BUTTON LIGHT WHEN THE GENERATOR CAME UP TO NORMAL OPERATING SPEED?','A.┬á┬á┬á┬á┬á Gen fault amber light should go out;','B.┬á┬á┬á┬á┬á It would go out, but only after the button was cycled;','C.┬á┬á┬á┬á┬á White OFF light remains illuminated.','*','A'),(367,3,'ELECTRICAL','IN FLIGHT ONE ARROW ILLUMINATED ON THE EMERGENCY SUPPLY SHOWS:','A.┬á┬á┬á┬á┬á The supply of DC STBY BUS from DC EMER BUS, according to one illuminated;','B.┬á┬á┬á┬á┬á The supply of DC ESS or DC EMER BUS from the corresponding HOT BATTERY BUS and battery discharging;','C.┬á┬á┬á┬á┬á The supply of DC EMER BUS from DC BUS 1 or DC BUS 2.','*','B'),(368,3,'ELECTRICAL','THE \"DC BTC\" IS AUTOMATICALLY CLOSED AND THE FLOW BAR IS ILLUMINATED IN CASE OF:','A.┬á┬á┬á┬á┬á EXT PWR operation only;','B.┬á┬á┬á┬á┬á HOTEL MODE operation only;','C.┬á┬á┬á┬á┬á EXT PWR operation, HOTEL MODE operation, or single engine operation.','*','C'),(369,3,'ELECTRICAL','IN THE EVENT OF BOTH DC BUS 1 AND DC BUS 2 SUPPLY LOST:','A.┬á┬á┬á┬á┬á INV 1 is automatically supplied by DC SVCE BUS;','B.┬á┬á┬á┬á┬á INV 1 is automatically supplied by the HOT MAIN BAT BUS  or by the HOT EMER BAT BUS in OVRD configuration (or by TRU if  equipped and selected on);','C.┬á┬á┬á┬á┬á INV 1 is not supplied.','*','B'),(370,3,'ELECTRICAL','NOT COUNTING UTILITY AND SERVICE BUSSES, WHICH DC/AC BUSSES CANNOT BE SUPPLIED WHEN ON BATTERIES ONLY?','A.┬á┬á┬á┬áDC1 - DC2 -AC1 - AC2','B.┬á┬á┬á┬á┬áDC1 - DC2 - AC1- AC2 -AC STBY','C.┬á┬á┬á┬á┬á┬áDC1 - DC2 -DC STBY  AC1- AC2 -AC STBY','*','A'),(371,3,'ELECTRICAL','AIRCRAFT EQUIPPED WITH TRU, IN CASE OF DUAL GENERATOR LOSS:','A.┬á┬á┬á┬á┬á Automatically the ACW BUS 1 via TRU supplies the MAIN and the EMER BATTERIES;','B.┬á┬á┬á┬á┬á With TRU PB ON, the ACW BUS 2 is connected to DC EMER BUS, DC STBY BUS, INV 1 (AC STBY BUS only);','C.┬á┬á┬á┬á┬á With TRU PB ON, the ACW BUS 2 is connected to DC BUS 2 to recuperate the total DC ELECTRICAL SYSTEM.','*','B'),(372,3,'ELECTRICAL','WITH BATTERIES ONLY, AC BUS 1 AND AC BUS 2 ARE:','A.┬á┬á┬á┬á┬á Never supplied;','B.┬á┬á┬á┬á┬á Supplied only when BAT selector is on OVRD;','C.┬á┬á┬á┬á┬á Supplied when STBY BUS push-button is on OVRD.','*','A'),(373,3,'ELECTRICAL','BAT SELECTOR TOGGLE SW ON OVRD MEANS THAT:','A.┬á┬á┬á┬á┬á DC/AC STBY BUSSES are transferred from DC ESS BUS to DC EMER BUS;','B.┬á┬á┬á┬á┬á No changing about the supply, each EMER, ESS and STBY are forced to be connected to their respective batteries, overriding all other logics and protections;','C.┬á┬á┬á┬á┬á Each BAT continues to be charged by its respective DC BUS.','*','B'),(374,3,'ELECTRICAL','THE UNDV LIGHT ILLUMINATES AMBER WHEN:','A.┬á┬á┬á┬á┬á DC STBY BUS voltage is lower than 19.5 Volts;','B.┬á┬á┬á┬á┬á Battery voltage is below 26.5 Volts;','C.┬á┬á┬á┬á┬á ACW GEN voltage is below 115 Volts.','*','A'),(375,3,'ELECTRICAL','STBY BUS OVRD PUSH-BUTTON SET ON OVRD MEANS THAT:','A.┬á┬á┬á┬á┬á DC STBY BUS and AC STBY BUS through INV 1 are supplied from DC HOT EMER BUS;','B.┬á┬á┬á┬á┬á DC STBY BUS and AC STBY BUS through INV 1 are supplied from DC BUS 2;','C.┬á┬á┬á┬á┬á DC STBY BUS and AC STBY BUS through INV 1 are supplied from DC HOT MAIN BAT BUS.','*','A'),(376,3,'ELECTRICAL','NO EXT PWR AVAILABLE, DOES OPERATION IN HOTEL MODE PROVIDE POWER FOR THE ACW SYSTEM?','A.┬á┬á┬á┬á┬á Yes;','B.┬á┬á┬á┬á┬á No;','C.┬á┬á┬á┬á┬á Yes with ENG 2 CL at MAX RPM.','*','B'),(377,3,'ELECTRICAL','HOW CAN THE ACW SVCE BUS BE POWERED BY ACW EXT PWR:','A.┬á┬á┬á┬á┬á Directly from ACW EXT PWR, green AVAIL light illuminated;','B.┬á┬á┬á┬á┬á Directly from ACW EXT PWR, green AVAIL light illuminated, but the attendant panel ACW SVCE BUS SWITCH must be ON (light illuminated);','C.┬á┬á┬á┬á┬á From ACW BUS 1 regardless of attendant panel ACW SVCE BUS SWITCH position.','*','B'),(378,3,'ELECTRICAL','WHAT IS THE MINIMUM NP (PROP. SEED ROTATION), TO INSURE ACW GEN OPERATION?','A.┬á┬á┬á┬á┬á 45% (range of 341 to 488 Hz);','B.┬á┬á┬á┬á┬á 61.5% (range of 341 to 488 Hz);','C.┬á┬á┬á┬á┬á 70% (range of 341 to 488 Hz).','*','C'),(379,3,'ELECTRICAL','A/C ON GROUND AND ACW EXT PWR SELECTED ON, STARTING LH ENGINE AND PUTTING LH CL MAX RMP:','A)┬á┬á┬á┬á┬á ACW BUS 1 and ACW BUS 2 are supplied by RH ACW GEN;','B)┬á┬á┬á┬á┬á ACW BUS 1 and ACW BUS 2 are still supplied by ACW EXT PWR;','C)┬á┬á┬á┬á┬á ACW bus 1 is still supplied by ACW EXT PWR, ACW BUS 2 is supplied by ACW 2 GEN.','*','B'),(380,3,'ELECTRICAL','IN THE ACW SYSTEM, HOW MANY BTC (BUS TIE CONTACTORS) ARE USED?','A)┬á One BTC and one BTC PB;','B)┬á Two BTC and one BTC PB;','C)┬á Four BTC and two BTC PB.','*','B'),(381,3,'ELECTRICAL','THE BUS TIE CONTACTOR (BTC) IN THE ACW ELECTRICAL SYSTEM PERMITS:','A.  If one ACW GEN fails, the other provides power to both ACW busses;','B.┬á To provide power to both ACW busses EXT PWR is used;','C.┬á A and B are correct.','*','C'),(382,3,'ELECTRICAL','A/C ON GROUND, ENGINES RUNNING, EXT ACW PWR SUPPLYING THE BUSSES, WE SELECT ACW BTC ON ISOL:','A.┬á┬á┬á┬á┬á ACW BUS 1 is supplied by EXT PWR, ACW BUS 2 is supplied by ACW GEN 2;','B.┬á┬á┬á┬á┬á ACW BUS 1 is supplied by EXT PWR, ACW BUS 2 is lost;','C.┬á┬á┬á┬á┬á ACW BUS 1 and 2 are lost.','*','C'),(383,3,'ELECTRICAL','WITH ALL 4 AIRCRAFT GENERATORS PUSH-BUTTON IN (DEPRESSED), AND EXT PWR SUPPLYING BOTH ACW AND DC, SWITCH LIGHT SHOULD BE ILLUMINATED IN THE FOUR SHIPÔÇÖS GENERATOR PUSH-BUTTON?','A.┬á┬á┬á┬á┬á Amber FAULT, to show an opening generator contactor;','B.┬á┬á┬á┬á┬á White OFF;','C.┬á┬á┬á┬á┬á Nothing.','*','A'),(384,3,'ELECTRICAL','A/C IN FLIGHT, ACW GEN 1 FAILS:','A.┬á┬á┬á┬á┬á All ACW busses remain supplied by ACW GEN 2;','B.┬á┬á┬á┬á┬á ACW SVCE BUS only is shed;','C.┬á┬á┬á┬á┬á ACW BUS 1 is lost.','*','B'),(385,3,'ELECTRICAL','WHEN THE ACW SVCE BUS IS SHED, WHAT INDICATION(S) IS/ARE GIVEN?','a.┬á┬á┬á┬á┬á None;','b.┬á┬á┬á┬á┬á SHED amber light on attendant panel ACW SVCE BUS push-button;','c.┬á┬á┬á┬á┬á SHED amber light in overhead MAIN ELECT PANEL DC SVCE/UTILY push-button.','*','B'),(386,3,'FIRE','WHICH OF THE FOLLOWING AGENT IS USED IN THE TWO ENGINE FIRE BOTTLES?','A. Freon or halon, pressurized by nitrogen.','B. C02.','C. Chemical powder.','*','A'),(387,3,'FIRE','HOW MANY ENGINE FIRE EXTINGUISHER BOTTLES ARE THERE?','A. One for each engine.','B. Two for each engine.','C. Two common for both engines.','*','C'),(388,3,'FIRE','EACH ENGINE IS EQUIPPED WITH:','A. Two fire detection loops mounted in series.','B. Two fire detection loops mounted in parallel','C. Only one fire detection loop.','*','B'),(389,3,'FIRE','WHICH OF THE FOLLOWING BUSSES POWER THE ENGINE FIRE DETECTION SYSTEM THE FIRE HANDLES AND) THE EXTINGUISHER BOTTLE DISCHARGE SYSTEM?','A. AC STBY BUS.','B. DC BUS 1 left engine and DC BUS 2 right engine.','C. DC EMER BUS.','*','C'),(390,3,'FIRE','WHAT AURAL WARNING IS GIVEN IN CASE OF A FIRE WARNING OR A SMOKE WARNING?','A. Bell.','B. Continuous repetitive chime.','C. Cavalry charge.','*','B'),(391,3,'FIRE','WHAT HAPPENS WHEN THE \"SQUIB TEST\" PUSH-BUTTON IS DEPRESSED?','A. DISCH illuminates amber and CCAS is activated.','B. Discharge heads are tested and two SQUIB lights illuminate white.','C. Discharge heads are tested and CCAS is activated.','*','B'),(392,3,'FIRE','SWITCHING THE \"FIRE TEST SW\" ON FAULT POSITION, ON ENGINE FIRE PANEL, WHAT HAPPENS?','A) Only the related LOOP A and LOOP B FAULT lights illuminated, when the system is supplied by battery only.','B) The related LOOP A and LOOP B FAULT lights illuminate, with the CCAS panel LOOP light, MASTER CAUTION and aural advise in HOTEL MODE operation.','C) A and B are correct.','*','C'),(393,3,'FIRE','A/C ON GROUND, SUPPLIED BY BATTERY ONLY, BOTH CONDITION LEVERS IN SHUT-OFF POSITION THE FIRE TEST WILL OPERATE?','A. Engine fire light on CAP and in fire handle, the red light in CL.','B. Engine fire light on CAP and in fire handle, MASTER WARNING lights and CRC in CM1 loudspeaker.','C. Engine fire light on CAP and in fire handle, MASTER CAUTION lights and CRC in both loud speakers.','*','B'),(394,3,'FIRE','TO GET THE FIRE WARNING ON, IT IS NECESSARY TO HAVE.','A. Both loops ON.','B. One loop ON only, but the other at OFF.','C. A and B are correct.','*','C'),(395,3,'FIRE','ENGINE FIRE TEST, LOOP PUSH-BUTTONS DEPRESSED (IN), WHAT HAPPENS IF ONLY ONE LOOP SENSES A FIRE?','A. Nothing.','B. \"FAULT\" illuminates in the associated push-button and LOOP amber light illuminates on CCAS panel.','C. Fire warnings are initiated.','*','A'),(396,3,'FIRE','WITH ONLY ONE LOOP PUSH-BUTTON IN ON POSITION (the other in OFF), WHAT HAPPENS IF IT SENSES A FIRE?','A. Nothing.','B. \"FAULT\" illuminates in the associated push-button and \"LOOP\" amber light illuminates on CCAS panel.','C. Fire warning is initiated.','*','C'),(397,3,'FIRE','WHEN AN ENGINE FIRE WARNING APPEARS, WHICH WARNINGS ARE INITIATED?','A. MASTER WARNING plus CRC (aural alarm) ENG FIRE red light on CAP and Fire handle red light','B. Answer A plus FUEL Shut OFF red light into the associated CL (provided CL is not in fuel S/O position).','C. Answer A and B plus LOOP light on CAP.','*','B'),(398,3,'FIRE','THE FUEL SHUT OFF RED LIGHT IN THE CL ILLUMINATES:','A. During fire detection test (CL at fuel shut-off position).','B. During a real fire (CL is not in fuel shut-off position).','C. A and B are correct.','*','B'),(399,3,'FIRE','IS IT POSSIBLE TO DISCHARGE A FIRE BOTTLE WITHOUT PULLING THE FIRE SHUT-OFF HANDLE?','A. Yes.','B. Manually only.','C. No.','*','C'),(400,3,'FIRE','WHEN YOU PULL THE ENG FIRE SHUT-OFF HANDLE, WHAT HAPPENS?','A. Propeller feathering, fuel engine low pressure valve closure, air bleed valve and HP valve closure, DE ICE valve and SHUT-OFF valve closure, electrical DC and ACW generators deactivation, SQUIB light illumination, extinction agent push-button is activa','B. Answer A plus HYD system isolation.','C. Answer A plus UPTRIIM PWR on the other engine.','*','A'),(401,3,'FIRE','THE \"DISCH\" AMBER LIGHT INDICATES:','A. A successful discharge head test','B. Fire bottle is empty (depressurized).','C. The push-button to depress in order to discharge a bottle.','*','B'),(402,3,'FIRE','FIRE PROCEDURE ON LEFT ENGINE, AFTER AGENT 1 DISCHARGE, YOU SEE:','A. Agent 1 DISCH on left engine only.','B. Agent 1 DISCH on left engine + agent 1 DISCH on right engine.','C. Agent 1 DISCH on left engine + agent 2 DISCH on right engine.','*','C'),(403,3,'FIRE','AFTER AN ENGINE FIRE, WHEN DOES THE RED FIRE HANDLE LIGHT EXTINGUISH?','A. Only when the temperature detected by the loops drops below the warning threshold.','B. Either when the temperature has dropped below the trigger level or, as soon as the fire handle has been pulled','C. Either when the temperature has dropped below the trigger level or, when one fire bottle has been discharged.','*','A'),(404,3,'FIRE','SMOKE DETECTORS ARE PROVIDED:','A. In the cockpit, the cabin, the cargo compt','B. In the cockpit, the avionics compt. and the cargo compt.','C. In the avionics compt., toilet and the forward and after cargo compt.','*','C'),(405,3,'FIRE','A RED \"ELEC SMK LIGHT ON THE \"CAP\" PANEL CAN INDICATE SMOKE DETECTED IN THE AIR EXTRACTION DUCT FROM WHICH OF THE FOLLOWING AREAS?','A. Flight deck.','B. Between the avionics compartment and the extract fun.','C. Avionics compartment','*','B'),(406,3,'FUEL','FUEL QUANTITY INDICATORS DISPLAY:','A. Fuel mass remaining on board.','B. Total consumption since engines start.','C. Fuel volume remaining on board.','*','A'),(407,3,'FUEL','THE ELECTRICAL PUMP AND THE JET PUMP ARE LOCATED:','A. Both in a feeder compartment, to avoid uncovering the pumps in case of vertical or lateral loads.','B. Both in each main wing tank, lower position.','C. Electrical pump in lower position, jet pump in upper position of the main wing tank.','*','A'),(408,3,'FUEL','ENGINE FEED DESCRIPTION:','A. Neither the electrical pump nor the jet pump can circulate fuel in reverse direction through the other.','B. EXCESS FLOW (fuel not able to flow through the LP VALVE towards the HMU) from either the electrical pump or jet pump, returns to an anlet supplying the feeder compartment insuring that it is always full.','C. A and B are correct.','*','C'),(409,3,'FUEL','IN NORMAL OPERATION, THE ELECTRICAL PUMP IN EACH TANK IS USED ONLY TO:','A. Start the engine, which pressurizes the jet pump via its HMU HP fuel pump for subsequent pressurization of the fuel system.','B. Pressurize the jet pump, which pressurizes the fuel system for engine start and subsequent normal operation.','C. Provide the additional flow required for take-off, since the jet pump alone is incapable of maintaining such a high rate of flow.','*','A'),(410,3,'FUEL','THE TWO FUEL PUMP PUSH-BUTTONS CONTROL WHICH OF THE FOLLOWING?','A. Automatic starting and stopping function of the related electrical pump when selected in (depressed).','B. Closure of the related motive flow valve, thus shut-off of the related jet pump when selected OFF (released).','C. A + B are correct.','*','C'),(411,3,'FUEL','THE ELECTRICAL PUMP NORMALLY RUNS ANYTIME THE RELATED PUMP PB IS IN (DEPRESSED) AND:','A. Return pressure from the HMU is below  8,5 PSI (500mb).','B. During crossfeed operation, X-FEED push-button IN (depressed).','C. Both A and B are correct','*','C'),(412,3,'FUEL','WHEN DOES THE \"MOTIVE FLOW VALVE\" OPEN?','A. Anytime the related PUMP PUSH-BUTTON is IN (depressed).','B. Anytime the related PUMP PUSH-BUTTON is IN (depressed), and pressure from the HMU is sufficient to open it','C. Whenever the electric pump is weak.','*','B'),(413,3,'FUEL','JET PUMP IS ACTIVATED BY:','A. HP fuel from electrical pump.','B. HP fuel from engine HMU.','C. Both A and B are correct.','*','B'),(414,3,'FUEL','IN THE WHOLE FLIGHT ENVELOPE, HOW MANY ENGINES CAN ONLY ONE ELECTRIC FUEL PUMP SUPPLY?','A. Only one.','B. Both engines.','C. Jet pump supply is necessary for take-off.','*','A'),(415,3,'FUEL','THE FUEL TANK MAXIMUM CAPACITY IS:','A. 2868 lit. (758 US GAL) per tank, 5736 lit. (1516 Us GAL) total.','B. 2250 Kg (4960 Lb.) per tank, 4500 Kg (9920 Lb.) total (0.785).','C. Both A and B are correct.','*','C'),(416,3,'FUEL','A JET PUMP FAILURE IS DETECTED BY:','A. illumination of FEED LO PR and CCAS activation.','B. illumination of RUN green light in the related electrical fuel pump PB.','C. A+B are correct.','*','B'),(417,3,'FUEL','ENGINE RUNNING, THE ILLUMINATED LIGHT \"FEED LO PR\" ASSOCIATED   WITH \"CCAS\" ACTIVATION CAN MEANS:','A. Pressure drops below 4 PSI or fuel starvation.','B. Electrical pump failure.','C. Jet pump failure.','*','A'),(418,3,'FUEL','TO FEED ENG  N┬░1 WITH TANK N┬░2, LH AND RH FUEL  PUMPS RUNNING,  YOU MUST:','A. Open the crossfeed valve only.','B. Open the crossfeed valve, and select engine n┬░1 FUEL PUMP PB OFF.','C. Select engine n┬░1 FUEL PUMP PB OFF, and open the crossfeed valve.','*','B'),(419,3,'FUEL','DURING CROSSFEED OPERATION, HOW MANY PUMPS ARE RUNNING?','A. One, the jet pump in the side with the most fuel.','B. Two, elect and jet pumps on the side with the most fuel.','C. Three, both electrical pumps and the jet pump on the side with the most fuel.','*','B'),(420,3,'FUEL','IF NO GREEN \"FLOW BAR\" IS VISIBLE IN THE \"X-FEED\" PUSH-BUTTON,  WHAT DOES IT MEAN?','A. Crossfeed valve is closed.','B. Crossfeed valve is open, but no fuel is being transferred.','C. Crossfeed valve is in transit, or a fault exist','*','C'),(421,3,'FUEL','HOW IS THE \"LP VALVE\" AT THE OUTLET OF EACH TANK CONTROLLED?','A. Mechanically by the related fire handle.','B. Electrically by the related fire handle (DC BUS 1 or 2 for the motor 1, DC EMER BUS or  HOT EMER BAT BUS for the motor 2).','C. By the related CONDITION LEVER.','*','B'),(422,3,'FUEL','\"LO LVL\" AMBER LIGHT AND \"CCAS\" ACTIVATED MEANS THAT:','A. Fuel quantity becomes lower a 160 Kg and the fuel cross feed opens automatically.','B. Fuel quantity becomes lower a 160 Kg and the corresponding electrical pump runs automatically.','C. Fuel quantity becomes lower a 500 Kg.','*','B'),(423,3,'HYDRAULIC','EACH HYDRAULIC SYSTEM IS MAINLY PRESSURIZED BY MEANS OF:','A. An engine driven pump.','B. An ACW electrical pump.','C. An alternate pump.','*','B'),(424,3,'HYDRAULIC','AN AUXILIARY DC ELECTRICAL PUMP IS LOCATED:','A. In the BLUE HYD SYSTEM.','B. In the GREEN HYD SYSTEM.','C. In both HYD SYSTEM.','*','A'),(425,3,'HYDRAULIC','THE NORMAL HYDRAULIC PRESSURE OF THE BLUE AND GREEN  SYSTEM IS:','A. 1500 PSI.','B. 2000 PSI.','C. 3000 PSI.','*','C'),(426,3,'HYDRAULIC','THE HYDRAULIC FLUID IS CONTAINED IN:','A. Two separated tanks (BLUE in the LH landing gear fairing, GREEN in the RH landing  gear faring).','B. A single common pressurized tank located in the hydraulic bay (LH landing gear fairing).','C. A single common not pressurized tank, divided in two compartments BLUE and GREEN,  located in the hydraulic bay (LH landing gear fairing).','*','C'),(427,3,'HYDRAULIC','WHAT IS THE NORMAL ACCUMULATOR PRE-CHARGE PRESSURE ON  THE THREE GAGES NEAR THE LEFT MAIN GEAR BAY:','A. 800 PSI.','B. 1500 PSI','C. 3000 PSI.','*','B'),(428,3,'HYDRAULIC','THE USERS OF THE BLUE HYDRAULIC SYSTEM ARE:','A. Nose wheel steering, flaps, spoilers, propeller brake.','B. Nose wheel steering, flaps, spoilers, propeller brake, emergency and parking brake.','C. Landing gear, emergency and parking brake.','*','B'),(429,3,'HYDRAULIC','THE USERS OF THE GREEN HYD SYSTEM ARE:','A. Landing gear and normal brakes.','B. Nose wheel steering, landing gear and normal brakes.','C. Landing gear, normal brakes and parking brake.','*','A'),(430,3,'HYDRAULIC','ON GROUND WITHOUT ELECTRICAL POWER (BAT SW OFF), WE CAN  READ:','A. Hydraulic pressure or gas pressure gage on the hydraulic bay (LH landing gear fairing).','B. Hydraulic pressure or gas pressure gage in the cockpit','C. A + B are correct.','*','A'),(431,3,'HYDRAULIC','ON GROUND, PUSHING THE \"AUX PUMP PB\" ON THE PEDESTAL,  ALLOWS:','A. To energize the AUX PUMP, providing BAT SW \"ON\" position.','B. To energize the AUX PUMP, which pressurize the BLUE HYDRAULIC SYSTEM, regardless BAT SW \"ON\" or \"OFF position.','C. To pressurize the GREEN HYDRAULIC SYSTEM.','*','B'),(432,3,'HYDRAULIC','WITH THE AIRCRAFT ON GROUND AND RIGHT ENGINE RUNNING AT  MAX RPM, THE FOLLOWING MAIN PUMPS ARE ACTIVATED:','A. Only BLUE.','B. BLUE and GREEN.','C. Only GREEN.','*','B'),(433,3,'HYDRAULIC','WHEN PROPELLER BRAKE LOCKING SEQUENCE IS INITIATED (ENGINE   ONE STOPPED, ENGINE TWO RUNNING):','A. AUX PUMP runs automatically for two minutes.','B. AUX PUMP stops to run when propeller brake is engaged.','C. AUX PUMP pedestal switch has to be pressed, to pressurize the BLUE SYSTEM.','*','B'),(434,3,'HYDRAULIC','THE \"AUX PUMP\" RUNS AUTOMATICALLY (PB PRESSED):','A. In flight: low pressure in the BLUE SYSTEM, landing gear lever is selected down, at least   one engine running.','B. On ground: low pressure in the BLUE SYSTEM, propeller brake not engaged, at least one   engine running.','C. A+B are correct.','*','C'),(435,3,'HYDRAULIC','WHEN A \"LOW PRESSURE\" AMBER LIGHT ON GREEN HYDRAULIC PUMP  PB COMES ON, THE CROSS-FEED VALVE AUTOMATICALLY OPENS:','A. True.','B. False.','C. Depending of the BLUE pressure only.','*','B'),(436,3,'HYDRAULIC','IN CASE OF \"BLUE HYDRAULIC MAIN PUMP LO PRESS\" ALERT (IN  FLIGHT GEAR UP):','A. AUX PUMP takes over automatically.','B. AUX PUMP takes over automatically, if GREEN PRESSURE is not available.','C. AUX PUMP does not take over automatically.','*','C'),(437,3,'HYDRAULIC','WITH BOTH \"BLUE HYD PUMPS OFF\", AND \"GREEN HYD PUMP\"   RUNNING, CROSS-FEED ALLOWS PRESSURIZATION OF:','A. BLUE system, except braking accumulator.','B. Both, BLUE system and braking accumulator.','C. Only the braking accumulator.','*','B'),(438,3,'HYDRAULIC','ON FINAL APPROACH, GEAR DOWN, NORMAL CONDITIONS, AN AMBER \"LO PRESS\" LIGHT ILLUMINATES ON THE BLUE MAIN PUMP:','A. You lose both, the BLUE MAIN PUMP and the AUX PUMP and you must open the  CROSS-FEED to restore the BLUE pressure.','B. Automatically the AUX PUMP restores BLUE pressure.','C. Automatically the CROSS-FEED restores the BLUE pressure.','*','B'),(439,3,'HYDRAULIC','THE \"OVHT\" ALERT INDICATES:','A. Overheat of the hydraulic fluid reservoir.','B. Overheat in the return line.','C. Overheat of the pump case drain line.','*','C'),(440,3,'HYDRAULIC','IN CASE OF LOW LEVEL ALERT','A. CROSS-FEED VALVE is automatically closed, but can be open after gear extension.','B. CROSS-FEED VALVE is automatically closed and inhibited.','C. CROSS-FEED VALVE has to be closed manually.','*','B'),(441,3,'HYDRAULIC','IN CASE OF DUAL DC GENERATORS LOSS:','A. DC AUX PUMP only is lost','B. DC AUX PUMP and GREEN MAIN HYD PUMP are lost.','C. DC AUX PUMP and CROSS-FEED VALVE are lost','*','A'),(442,3,'ICE','AIRCRAFT ICE PROTECTION IS PROVIDED BY:','A. Pneumatic system only.','B. Electrical heating only.','C. Electrical heating and pneumatic system.','*','C'),(443,3,'ICE','NTI ICING ELECTRICAL HEATING IS PROVIDED MAINLY BY ACW   CURRENT FOR:','A. Propeller blades, windshields and probes only.','B. Propeller blades, windshields, probes, flight control horns.','C. Propeller blades, windshields, probes, engine air intakes.','*','B'),(444,3,'ICE','ON THE DE-ICING PANEL, THE AIR FRAME AIR BLEED PB:','A. Must be IN, no OFF light, in order to operate engine and wing stabilizer boots.','B. Can be OFF, OFF light on, in order to operate engine boots (engine de-icing selected ON).','C. A + B are correct.','*','C'),(445,3,'ICE','THE PURPOSE OF \"AIR FRAME AIR BLEED\" IS?','A. To control DE ICE and ISOLATION VALVES normal operation, PB pressed both DE- ICE and ISOLATION VALVES are open.','B. To permit a detection of an ENGINE or AIR FRAME DE ICE SYSTEM failure.','C. A+B are correct.','*','C'),(446,3,'ICE','BOTH, AIR FRAME AND ENGINE DE ICING SELECTED ON, THEY ARE:','A. De iced simultaneously.','B. De iced sequentially.','C. Totally independent one from each other.','*','B'),(447,3,'ICE','DE ICING LIGHT ILLUMINATES ON MEMO PANEL WHEN:','A. Air frame de icing is selected ON','B. Ice is detected by ICE DETECTOR SYSTEM.','C. Window and probe heat are ON','*','A'),(448,3,'ICE','MODE SEL AUTO IN \"MAN\" ON THE DE ICING PANEL, WHEN SHOULD THE    \"MODE SEL PB\" BE \"ON\"?','A. If SAT above -20 C; causes a cycle length of 60 sec.','B. If SAT below -20 C; causes a cycle length of 60 sec.','C. If SAT below -20 C; causes a cycle length of 180 sec.','*','C'),(449,3,'ICE','CAN YOU USE THE \"PNEUMATIC DE ICING SYSTEM\" WITH BOTH ENGINE BLEED VALVES \"OFF\", ENGINES RUNNING?','A. Yes','B. No.','C. Yes but except ENGINE DE ICE.','*','A'),(450,3,'ICE','WITH ONE ENGINE INOPERATIVE, ARE BOTH SIDES OF THE \"AIR FRAME  DE ICING SYSTEM\" SUPPLIED?','A. No.','B. Yes.','C. Yes, provide that tire handle has been pufled.','*','B'),(451,3,'ICE','AIRCRAFT IN FLIGHT, IF THE \"AAS\" SYSTEM DETECTS ICE WHILE ICING  \"AOA\" GREEN LIGHT IS EXTINGUISHED:','A. The amber ICING light illuminates steady, MASTER CAUTION and single chime.','B. The amber ICING light illuminates flashing, MASTER CAUTION and single chime.','C. The green ICING AOA illuminates.','*','B'),(452,3,'ICE','AIRCRAFT IN FLIGHT, IF THE \"AAS\" SYSTEM DETECTS ICE, \"AOA\"  GREEN LIGHT IS ILLUMINATED:','A. The amber ICING light illuminates steady, MASTER CAUTION and single chime.','B. The green ICING AOA light illuminates flashing.','C. The DE ICING light on memo panel illuminates flashing.','*','A'),(453,3,'ICE','AIRCRAFT IN FLIGHT, WE NOTICE THE BLUE LIGHT \"DE ICING\"  FLASHES ON MEMO PANEL:','A. The AAS system detects ice when the AIR FRAME DE ICING system is \"OFF\".','B. The AAS system detects ice and the AIR FRAME DE Icing system operates normally.','C. The AIR. FRAME DE ICING system is still \"ON\" five minutes after the last ice accretion is  detected by the AAS system.','*','C'),(454,3,'ICE','FAULT LIGHT IN AIRFRAME AIR BLEED \"PB\" illuminates AMBER AND \"CCAS\" IS ACTIVATED WHEN:','A. Air pressure downstream of the de-ice valves stays below 14 PSI, more than 10 sec., or air  temperature upstream of the de-ice valves exceeds 230┬░ C.','B. Inflation sequence of AIRFRAME BOOTS A or B is not correct.','C A+B are correct.','*','C'),(455,3,'ICE','DE ICING OVERRIDE \"PB\" IN \"OVRD\" POSITION:','A. By-passes the MFC modules logic an a timing cycle of 60 sec is selected.','B. It is used only when associated fault light is illuminated.','C. A + B are correct.','*','C'),(456,3,'ICE','MODE SEL AUTO PB IN \"MAN\" POSITION:','A. The DE ICING MODE SEL PB is inoperative, (FAST mode is automatically activated).','B. DE ICING MODE SEL ph is operative and allows the crew to select the appropriate  timing cycle, depending on SAT.','C. Is used when ADC + MFC failure occurs, in this case the FAST mode is automatically  activated.','*','B'),(457,3,'ICE','NORMAL OPERATION, WHEN IS IT POSSIBLE TO USE PROPELLER ANTI  ICING?','A. Only when NP are above 63 %.','B. Only when both engines are running.','C. Only when SAT is below zero.','*','A'),(458,3,'ICE','PROPELLER ANTI ICING MODE SELECTOR, SELECTED \"ON\":','A) Blades heating is 20 sec. long according to a cycle of 80 sec.','B) Blades heating is 10 sec. long according to a cycle of 70 sec.','C) Blades heating duration is the same but more frequent','*','A'),(459,3,'ICE','STALL ALERT THRESHOLD IS REDUCED FROM NORMAL OPERATION TO  ICING OPERATION AS SOON AS:','A)  Ice accretion is detected.','B) Propellers and horns anti icing are selected ON.','C) At least one horn anti icing is selected ON.','*','C'),(460,3,'ICE','WHEN DOES THE GREEN LIGHT \"AOA\" DISAPPEAR?','A. Automatically, at the end of ice accretion, ICING amber light OFF.','B. Automatically, after horns anti ice OFF selection.','C. Manually by depressing AOA green light PB, after it is visually confirmed that the aircraft is clear of any residual ice.','*','C'),(461,3,'ICE','TO PREVENT THE FORMATION OF ICE ON AIR DATA SENSORS, ELECTRICAL PROBE HEATING IS PROVIDED FOR:','A. CAPT. F/O, STBY pitot tubes (3) and static ports (6) only.','B. CAPT. F/O, STBY pitot tubes (3) and static ports (6), CAPT and F/O angle of attack   probes (2), plus TAT (total air temperature) probes (2) in flight only.','C. B is correct, but TAT probe is heated on ground and in flight.','*','B'),(462,3,'ICE','PITOTS, PROBES AND STATIC PORTS ARE:','A. Heated and monitored by CCAS on ground and in flight (except static ports monitored by   CCAS on ground only).','B. Heated on ground and in flight but not monitored by CCAS.','C. Heated and monitored in flight only.','*','A'),(463,3,'ICE','PROBES HEATING AND WINDSHIELD HEATING PB \"ON\" IN HOTEL MODE  OPERATION:','A. PITOTS, TAT, angle of attack, probes are heated.','B. Windshields are heated.','C. Static ports and STBY pitot are heated.','*','C'),(464,3,'ICE','YOU CAN USE WINDSHIELD WIPERS:','A. Below 180 KTS','B. Below 160 KTS','C. At any speed.','*','B'),(465,3,'INSTRUMENTS','THE TWO AIR DATA COMPUTERS (ADC) ARE SUPPLIED WITH STATIC AIR  PRESSURE, TOTAL AIR PRESSURE, TOTAL AIR TEMPERATURE AND) EACH  ADC COMPUTES:','A. Pressure altitude, vertical speed and indicated air speed (lAS).','B. Pressure altitude, vertical speed, computed air speed (CAS), true air speed (TAS), ground  speed(GS) and STD air temperature. (ISA).','C. Pressure altitude, vertical speed, indicated air speed (lAS), true air speed (TAS), total air  temperature (TAT) and static air temperature (SAT).','*','C'),(466,3,'INSTRUMENTS','ADC 1 SUPPLIES:','A.┬áCAPT flight instruments, AHRS 1, ATC 1, FDAU, MFC, GPWS, pressurization, AFCS.','B.┬áEEC and TAT/SAT/TAS indicator are supplied according to ADC 1/2 selector on CAPT  PANEL.','C.┬á A+B are correct.','*','C'),(467,3,'INSTRUMENTS','ADC 2 SUPPLIES:','A. F/O flight instruments, AHRS 2, FDAU, MFC, pressurization, AFCS and ATC 2 (if  installed).','B. F/O flight instruments only.','C. F/O flight instruments and STBY SYSTEM.','*','A'),(468,3,'INSTRUMENTS','AN \"ADC 1\" FAILURE IS DETECTED BY:','A Red flags on CPT flight instruments and MASTER CAUTION.','B. Red flags on CPT flight instruments, lost of information on TAS/TAT SAT indicator and EECs failure if ADC SELECTOR 1 position.','C. Red flags on CPT fight instruments, AHRS 1 failure and lost of information on TAS/TAT/SAT indicator.','*','B'),(469,3,'INSTRUMENTS','AN \"ADC2\"FAILURE IS DETECTED BY:','A. Red flags on F/O flight instruments and lost of information on TAT/SAT/TAS indication and EECs failure if ADC selector in 2 position.','B. Red flags on F/O flight instruments and AFCS failure (A/P disconnection).','C. Red flags on F/O flight instruments, and AUTO PRESS. failure','*','A'),(470,3,'INSTRUMENTS','IN CASE OF \"ADC\" FAILURE:','A. Select the other ADC.','B. Compare valid ADC with the STBY INSTRUMENTS and select the other ADC to restore TAS/TAT/SAT indicator and EECs failure.','C. Reset the MASTER CAUTION and select the other ADC.','*','B'),(471,3,'INSTRUMENTS','AIRCRAFT IN FLIGHT, TOTAL DC GEN. LOSS:','A. ADC 1 only is supplied.','B. ADC1 and ADC 2 ares upplied.','C. STBY INSTRUMENTS only are available.','*','A'),(472,3,'INSTRUMENTS','THE TWO \"AHRS\"(ATTITUDE AND HEADING REFERENCE SYSTEM)  PROVIDE THE FOLLOWING DATA:','A. Pitch, roll, heading and ground speed.','B. Pitch, roll and heading.','C. Pitch, roll, heading, ground speed and ILS information.','*','B'),(473,3,'INSTRUMENTS','A/C ON GROUND, THE TWO \"AHRS\" START THEIR ALIGNMENT PERIOD:','A. Automatically provided aircraft batteries selected ON.','B. Automatically provided a DC and ACW EXT PWR is connected.','C. After first engine start and AHRS 1 and 2 selected ON.','*','A'),(474,3,'INSTRUMENTS','THE \"AHRS 1\" SUPPLIES:','A. SGU 1, F/O RMI, FDAU, Radar; ASCB BUS.','B. SGU 1, CPT RMI, FDAU, Radar, ASCB BUS.','C. SGU 1, F/O RMI,ASCB BUS.','*','A'),(475,3,'INSTRUMENTS','THE \"AHRS 2\" SUPPLIES:','A. SGU 2, CPT RMI, FDAU, Radar, ASCB BUS.','B . SGU 2, F/O RMI, ASCB BUS.','C. SGU 2, CPT RMI, ASCB BUS.','*','C'),(476,3,'INSTRUMENTS','WHEN THE \"ERECT/FAIL\" WARNING ILLUMINATES ON ONE \"AHRS\":','A. The crew must turn OFF this equipment and perform a switching to the remaining system.','B. The crew must turn OFF this equipment for a 5 minutes period, then start a new alignment  process.','C. The crew must press this switch during 15 seconds, while maintaining the aircraft on non-accelerated flight (straight and level) for gyro erection.','*','C'),(477,3,'INSTRUMENTS','AIRCRAFT IN FLIGHT SUPPLIED BY BATTERIES ONLY:','A. AHRS 1 only is supplied.','B. AHRS 1 and 2 are supplied.','C. STBY INSTRUMENTS only are operating.','*','A'),(478,3,'INSTRUMENTS','WHAT HAPPENS IN CASE OF AN \"AHRS\" FAILURE?','A. Single chime, HDG FAIL red message on associated EHSI and ATT FAIL red message on  associated EADI.','B. HDG FAIL red message on associated EHSI and ATT FAIL red message on associated   EADI and A/P disengages.','C. HDG FAIL red message on associated EHSI and ATT FAIL red message on associated   EADI, red flag on opposite RMI and A/P remains engaged.','*','C'),(479,3,'INSTRUMENTS','WHAT ACTION SHOULD BE PERFORMED IF AN \"AHRS\" FAILURE OCCURS ?','A. Pull the circuit breakers on the failed AHRS.','B. Pilot on the side of failed AHRS should select opposite ATT/HDG reference (ATT/HDG  push-button).','C. Pilot on the side of failed AHRS should select opposite SGU (SGU push-button).','*','B'),(480,3,'INSTRUMENTS','THE APPEARANCE OF AN AMBER \"ATT\" MESSAGE ON THE TOP RIGHT OF  THE EADI MEANS THAT:','A. Both pilots are using the same AHRS.','B. The AHRS pitch and roll data are not longer provided to the EFIS.','C. The two AHRS disagree on both pitch and roll information (6┬░ or more).','*','C'),(481,3,'INSTRUMENTS','THE APPEARANCE OF AN \"HDG\" AMBER MESSAGE ON THE TOP RIGHT OF  THE EADI MEANS THAT:','A. The two AHRS disagree on heading information (6┬░ or more).','B. The EFIS are not longer provided with the associated heading information.','C. Heading information comes from the other AHRS.','*','A'),(482,3,'INSTRUMENTS','WHEN THE TWO \"AHRS\" DISAGREE OF 6┬░ OR MORE, WHAT HAPPENS?','A. PIT, ROLL or ATT message is displayed on failed EADI','B. PIT, ROLL or ATT message is displayed on both EADI.','C. PIT, ROLL or ATT message is displayed on both EADI, EFIS COMP amber light on CAP  and A/P disengages for ATT only.','*','C'),(483,3,'INSTRUMENTS','WHAT CORRECTIVE ACTION SHOULD BE PERFORMED IF AN \"EFIS COMPARISON\" FAULT OCCURS?','A. Pull the circuit breaker of the incorrect AHRS.','B. Pilot on the side of the incorrect AHRS should select opposite ATT/HDG reference  (ATT/HDG push-button).','C. Compare both EADI to STBY ATT INSTRUMENT then perform steps A and B.','*','C'),(484,3,'INSTRUMENTS','WHAT ARE THE INDICATIONS OF A \"SGU\" FAILURE, IN PART \"A\" OR \"B\" ?','A. Both CRTs of the failed side go black.','B. Both CRTs of the failed side display a red X.','C. A red flags appears on both CRTs.','*','B'),(485,3,'INSTRUMENTS','WHAT ARE THE INDICATIONS OF A \"SGU\" FAILURE IN PART \"C\"?','A. Both CRTs of the failed side go black.','B. Both CRTs of the failed side display a red X.','C. A red flag appears on both CRTs.','*','A'),(486,3,'INSTRUMENTS','WHAT ACTION SHOULD BE PERFORMED IF A \"SGU\" FAILURE OCCURS?','A. Pull the circuit breaker of the failed SGU.','B. Pilot on the side of failed SGU should select opposite ATT/HDG reference (ATT/HDG Push-button).','C. Pilot on the side of failed SGU should select opposite SGU (SGU push- button).','*','C'),(487,3,'INSTRUMENTS','WHAT IS THE INDICATION OF A FAILED \"CRT\"?','A. The failed CRT goes black.','B. The failed CRT displays a red X.','C. If the A/P is engaged on the side of the failed CRT, all the modes are lost','*','A'),(488,3,'INSTRUMENTS','AFTER FAILURE OF A \"CRT\":','A. It should be switched OFF in order to obtain the COMPOSITE MODE on the remaining CRT.','B. SGU push-button should be used to recover the lost display.','C. Composite MODE appears automatically on the remaining CRT.','*','A'),(489,3,'INSTRUMENTS','WHICH OF THE FOLLOWING METHODS IS OR ARE USED TO DISPLAY A LOSS OF ONE OR MORE INDIVIDUAL READOUTS ON THE \"EADI\" AND/OR  \"EHSI\"?','A. Red crosses appear on scales (LOC/GS/ COURSE DEVIATION/SPD).','B. Amber dashes replace digital information (DH/RA/CRS/HDG/DIST/ GSPD or TTG).','C. Navigation pointers and/or course deviation bars disappear.','D. A+B+C are correct.','D'),(490,3,'INSTRUMENTS','AIRCRAFT IN FLIGHT SUPPLIED BY BATTERIES ONLY:','A. SGU 1 and SGU 2 are working.','B. SGU 1 supplies the four CRTs (switching SGU 1 in F/O side).','C. Only CAPTs EADI is working in COMP. MODE if the CAPTs EHSI is in OFF position.','*','C'),(491,3,'INSTRUMENTS','THE \"EADI FAST/ SLOW\" SCALE IS REFERENCED TO WHICH OF THE  FOLLOWING?','A. AIRSPEED INTERNAL BUG sets on CPTs airspeed indicator.','B. AIRSPEED INTERNAL BUG sets on corresponding airspeed indicator.','C. Selected IAS shown on ADU when in IAS mode.','*','B'),(492,3,'INSTRUMENTS','AIRCRAFT ON GROUND, \"FLIGHT RECORDER\" OPERATIONS:','A. FLIGHT RECORDER is OFF until one engine is started.','B. FLIGHT RECORDER can be energized by selecting ON the RCDR PB and dc-energized by   pushing the RESET PB.','C. A + B are correct','*','C'),(493,3,'INSTRUMENTS','\"COCKPIT VOICE RECORDER\" OPERATIONS:','A. The last 30 minutes of recording are retained.','B. All recording may be erased by pressing ERASE PB provided the aircraft is on ground and parking brake is set ON.','C. A + B are correct.','*','C'),(494,3,'LANDING GEAR','THE LANDING GEAR POSITION INDICATIONS ARE CONTROLLED BY:','A. One system which controls two position indicators.','B. Two isolated systems, SYSTEM 1 and SYSTEM 2 and two separated position indicators.','C. Two isolated systems, SYSTEM 1 and SYSTEM 2 controlling one position indicator.','*','B'),(495,3,'LANDING GEAR','AIRCRAFT IS SUPPLIED BY BATTERIES ONLY:','A. SYSTEM 1 only is supplied (central panel).','B. SYSTEM 2 only is supplied (overhead panel).','C. Both SYSTEM 1 and SYSTEM 2 are supplied.','*','A'),(496,3,'LANDING GEAR','LANDING GEAR NOT DOWN, THE ALARM IS GENERATED:','A) By MFC 2 associated to the overhead panel (SYSTEM 2).','B) By MFC 1 associated to the central panel (SYSTEM 1).','C) A + B are correct.','*','C'),(497,3,'LANDING GEAR','AN ANTI RETRACTION LATCH PREVENTS SELECTION OF THE LANDING   GEAR LEVER TO THE \"UP\" POSITION AS LONG AS:','A. Nose landing gear shock absorbers sense weight on wheels.','B. The three landing gear shock absorbers are not extended.','C. One of the main gear shock absorbers sense weight on wheels.','*','B'),(498,3,'LANDING GEAR','THE \"LANDING GEAR SELECTOR VALVE\" IS LOCATED IN THE LH MAIN  GEAR FAIRING, AND IS CONTROLLED ELECTRICALLY FROM WHICH  BUS?','A. ACW BUS 1.','B. DC STBY BUS.','C. DC BUS 2.','*','B'),(499,3,'LANDING GEAR','LANDING GEAR NORMAL OPERATIONS:','A. The main gear wheels are braked automatically as soon as the lever is selected up.','B. As soon as the gear is locked at it selected position, hydraulic pressure is released.','C. A and B are correct.','*','C'),(500,3,'LANDING GEAR','TO CONSIDER THE GEAR DOWN, 3 GREEN LIGHTS MUST BE  ILLUMINATED ON:','A. Both, overhead and central instrument panels.','B. Either, overhead or central instrument panel.','C. One panel only, the central instrument panel.','*','B'),(501,3,'LANDING GEAR','ON THE LANDING GEAR PANELS, \"UNLK\" LIGHT ILLUMINATES TO  INDICATE:','A. Uplock device has failed.','B. Downlock device has failed.','C. Respective gear not seen lockedin lever selected position, or on the ground, the uplock box not in the opened position.','*','C'),(502,3,'LANDING GEAR','A RED LIGHT INCORPORATED IN THE LANDING GEAR LEVER WILL ILLUMINATE AND \"CCAS\" WILL BE ACTIVATED WHENEVER ANY GEAR IS NOT SEEN DOWN AND LOCKED:','A. Flaps 35┬░ and Zra below 500 ft.','B. At least one POWER LEVER at Fi. and Zra below 500 ft.','C. A + B are correct','*','C'),(503,3,'LANDING GEAR','LANDING GEAR NOT LOCKED DOWN ON OVERHEAD PANEL, ONE \"PL AT \"FI\", THE OTHER ONE BELOW TAKE OFF POSITION AND Zra BELOW  500 FT, THE AURAL ALERT MAY BE SILENCED BY:','A. The retraction of at least one landing gear for 150 seconds or depressing MASTER WARNING light if flaps are not in 35┬░ position.','B. Using EMERGENCY AUDIO CANCEL if the flaps are in 35┬░ position.','C. A+B are correct.','*','C'),(504,3,'LANDING GEAR','IF THE NORMAL GEAR EXTENSION FAILS, EMERGENCY EXTENSION  HANDLE ALLOWS MECHANICAL UNLOCKING, THEN:','A. Landing gear extends because of a spring device.','B. Landing gear extends because of gravity, aerodynamic forces and gas actuator. Main landing gear is assisted by gas actuators and integrated springs, nose landing gear by a  mechanical device.','C. Landing gear extends because of a pneumatic device.','*','B'),(505,3,'LANDING GEAR','HOW MANY VALVES IN THE NOSE WHEEL STEERING SYSTEM MUST BE OPEN BEFORE NOSE WHEEL STEERING IS AVAILABLE:','A) Only the SOLENOID VALVE, which is controlled by a combination of shock absorber (MFC) and the NOSE WHEEL STEERING CONTROL SWITCH.','B) Only the SWIWEL VALVE, which is controlled by nose gear extension and retraction.','C) Both of the valves must be open to obtain a maximum LH or RH deflection of 60┬░.','*','C'),(506,3,'LANDING GEAR','THE NOSE WHEEL STEERING OPERATIONS:','A. Before take off, it will be maintained as soon as one gear stays on ground.','B. At landing, it will work wit nose gear locked down, nose and main shock absorbers compressed.','C. A + B are correct.','*','C'),(507,3,'LANDING GEAR','HOW LONG SHOULD THE ANTI-SKID \"F\" LIGHTS ILLUMINATE DURING A  TEST OF A NORMAL SYSTEM?','A. As long as the TEST push-button is depressed.','B. 10 seconds.','C. 6 seconds on the ground, 3 seconds in flight.','*','C'),(508,3,'LANDING GEAR','15. THE ANTI-SKID TEST IS INHIBITED AT WHEEL SPEEDS ABOVE:','A. 10 KTS','B. 17 KTS','C. Never.','*','B'),(509,3,'LANDING GEAR','THE ANTI-SKID PROTECTION IS OPERATIVE AT SPEEDS OVER:','A. 10 Kts.','B. 23 Kts.','C. 35 Kts.','*','A'),(510,3,'LANDING GEAR','IF AN ANTI-SKID CHANNEL FAILS, THE ANTI-SKID TEST SHOWS:','A. Related F light does not illuminate.','B. Related F light does not extinguish after the test','C. Related F light flashes.','*','B'),(511,3,'LANDING GEAR','WHEN \"F\" LIGHT ILLUMINATES ON THE ANTI-SKID PANEL:','A. ANTI-SKID is lost on associated wheel.','B. ANTI-SKID system is not activated','C. ANTI-SKID electrical supply is lost','*','A'),(512,3,'LANDING GEAR','THE ANTI-SKID SYSTEM USES WHICH ELECTRICAL BUSSES?','A. AC BUS 1.','B. DC BUS 1 for inboard wheels, DC BUS 2 for outboard wheels.','C. DC ESS BUS for inboard wheels, DC EMER BUS for outboard wheels.','*','C'),(513,3,'LANDING GEAR','IN CASE OF TOTAL HYDRAULIC SYSTEMS FAILURE, THE BRAKE ACCUMULATOR ALLOWS VIA THE PARKING/EMERGENCY BRAKE  HANDLE:','A. One application of braking force at full braking pressure.','B. At least 6 application of braking force at full emergency braking pressure without ANTI-SKID protection.','C. At least 6 application of braking force at full emergency braking pressure with ANTI-SKID  protection.','*','B'),(514,3,'LANDING GEAR','THE BRAKE AND TIRE HIGH TEMPERATURE PROTECTIONS CONSIST OF:','A. The HOT light on the central panel indicating a brakes temperature of 160┬░C or more.','B. Fuse plugs designed to release internal tire pressure at high temperature (177┬░C or more) on the main wheels.','C. A + B are correct.','*','C'),(515,3,'LANDING GEAR','THE GEAR WHEELS ARE BRAKED AFTER TAKE OFF:','A. All automatically, as soon as the pilot selects UP landing gear control lever.','B. Automatically main gear only, as soon as the pilot selects UP landing gear control lever.','C. By the pilot using brake pedals.','*','B'),(516,3,'LANDING GEAR','THE ANTI SKID SYSTEM IS PROVIDED FOR:','A. Locked wheel protection, to preclude tire scuffing for wheels speed more then 23 Kt.','B. Touch down protection, to preclude inadvertent brake application when spin up is below 35 Kt or for 5 sec., whichever occurs first.','C. A + B are correct','*','C'),(517,3,'MFC','THE MFC SYSTEM CONSISTS OF:','A.┬á┬á┬á┬á┬á One Computer;','B.┬á┬á┬á┬á Two independent computer with two modules A and B;','c)┬á┬á┬á┬á┬á Two computer with four independents modules 1A 1B 2A 2B.','*','C'),(518,3,'MFC','EACH MFC MODULE PROCESSES DATA RECEIVED FROM SEVERAL SYSTEMS AND:','A)┬áThe signals are taken into account by one or more modules, depending on the degree of reliability/safety required for the system;','B)┬áEach module is equipped with a self test system, monitoring correct operation of that module;','C) Each module is supplied by two separate electrical sources (28 VDC), primary an secondary;','D)┬á A + B + C are correct.','D'),(519,3,'MFC','THE MFC FUNCTIONS ARE:','A.┬á┬á┬á┬á┬á Monitoring, control and authorize operation of aircraft systems;','B.┬á┬á┬á┬á Manage system failure and flight envelope anomalies and command triggering of associated warnings in the CCAS;','c)┬á┬á┬á┬á┬á A + B are correct.','*','C'),(520,3,'MFC','AN INTERNAL COMMUTATION ALLOW AN AUTOMATIC SWITCHING FROM NORMAL TO ALTERNATE ELECTRICAL SUPPLY, IF SOURCE VOLTAGE FALLS BELOW:','A.┬á┬á┬á┬á 19 VDC;','B.┬á┬á┬á┬á 22 VDC;','C.   ┬á 28 VDC.','*','A'),(521,3,'MFC','THE MFC IS OPERATIVE AS SOON AS CARGO DOOR CONTROL PANEL IS CLOSED AND:','A.┬á┬á┬á┬á┬á Battery is switch ON;','B.┬á┬á┬á┬á Battery is switched ON and modules self test is completed;','C.┬á┬á┬á┬á┬á DC BUS 1 or 2 are powered.','*','B'),(522,3,'MFC','THE MFC AMBER LIGHT COMES ON FLASHING IN 1A AND 2A MODULES TO INDICATE:','A.┬á┬á┬á┬á┬á Electrical supply fault is detected;','B.┬á┬á┬á┬á Self-test of these modules;','C.┬á┬á┬á┬á┬á A malfunction.','*','B'),(523,3,'MFC','WHEN A MODULE FAILURE IS DETECTED BY ITS INTERNAL MONITORING SYSTEM:','A.┬á┬á┬á┬á┬á Fault light only, on \"MFC\" panel, illuminates;','B.┬á┬á┬á┬á Single chime sound is triggered, MASTER CAUTION light flashes, MFC illuminates on CAP and associated amber fault light on overhead panel;','c)┬á┬á┬á┬á┬á Single chime is not triggered, MASTER CAUTION light illuminates steady and MFC illuminates on CAP.','*','B'),(524,3,'NAVIGATION','THE TWO \"NAV CONTROL BOX\" ON THE GLARESHEILD PANEL  CONTROL:','A. The respective VOR receivers using a common VOR antenna located on top of vertical stabilizer.','B. The respective ILS receivers using a common antenna, used for VOR (LOC information)  and a common GS antenna','C. A + B are correct.','*','C'),(525,3,'NAVIGATION','YOU CAN HAVE \"VOR INFORMATIONS ON:','A. EHSI and EADI course pointer and deviation.','B. EHSI course pointer and deviation, EADI deviation.','C. EHSI course pointer and deviation, EADI deviation in COMPOSITE MODE only, plus course pointers in RMI.','*','C'),(526,3,'NAVIGATION','YOU CAN HAVE \"ILS\" INFORMATIONS ON:','A. EHSI LOC and GS and EADI GS only.','B. EHSI and EADI LOC and GS.','C. EHSI and EADI LOC AND GS, plus VOR course pointer in RMI.','*','B'),(527,3,'NAVIGATION','COURSE POINTER INDICATIONS ON \"EHSI\" AND \"RMI\"','A. You can have NDB indication on RMI but not on EHSI.','B. You can have NDB indication on EHSI but not on RMI.','C. You can have NDB or VOR indication either on EHSI or in RMI depending of VOR ADF SELECTOR position.','*','C'),(528,3,'NAVIGATION','THE \"Nav \" INFORMATION \"VOR\" OR \"ILS\" DISPLAYED ON THE TOP RH PART OF THE \"EHSI\":','A. Identifies the NAV source used by the other pilot','B. Identifies the NAV source which supplies the COURSE DEVIATION BAR, (in AMBER  when both pilots are using the same system).','C. Identifies the NAV source which supplies the bearing pointer N┬░ 1.','*','B'),(529,3,'NAVIGATION','THE \"H\" IN FRONT OF THE \"DME\" MILEAGE INFORMATION ON THE \"EHSI\" MEANS THAT:','A. The other pilot has selected the same VOR DME frequency.','B. The concerned pilot has selected the HOLD DME MODE and will keep the distance   information even if the VOR/ILS frequency is changed.','C. A+B are correct.','*','B'),(530,3,'NAVIGATION','A \"VOR\" RECEIVER FAILURE IS SHOWN ON \"EHSI\" BY:','A. A red cross on DEVIATION BAR N┬░1, and the POINTER indication is removed if VOR is selected.','B. A red cross on DEVIATION BAR N┬░1, and the POINTER indication moves to 3 clock   position if VOR is selected.','C. A red cross on DEVIATION BAR N┬░1, MASTER CAUTION and EFIS COMPARISON.','*','A'),(531,3,'NAVIGATION','WHICH CORRECTIVE ACTION, CAN YOU TAKE IN CASE OF \"VOR 1  RECEIVER\" FAILURE?','A. Press F/O VOR ILS SWITCHING.','B. Press CAPT VOR/ILS SWITCHING, to transfer N.2 VOR RECEIVER on CAPT  deviation bar.','C. None.','*','B'),(532,3,'NAVIGATION','A \"GS 2 RECEIVER\" FAILURE IS SHOWN BY:','A. A red cross on EADI GS DEVIATION only.','B. A red cross on EADI 2 and EHSI 1 GS DEVIATION.','C. A red cross on EADI 2 and EHSI 2 GS DEVIATION.','*','C'),(533,3,'NAVIGATION','WHICH CORRECTIVE ACTION CAN YOU TAKE IN CASE OF \"GS 2  Receiver\" FAILURE?','A. Press CAPTs VOR/ILS switching.','B. Press F/Os VOR/ILS switching to transfer N┬░1 GS  receiver on F/O ILS indication.','C. Press F/O VOR/ILS switching to transfer N┬░1 ILS (LOC + GS) receiver on F/O ILS indication.','*','C'),(534,3,'PNEUMATIC','THE PNEUMATIC SYSTEM SUPPLIES PNEUMATIC AIR FOR:','A. Air conditioning, pressurization and pneumatic de-icing.','B. Air conditioning, pressurization and water system pressure.','C. Air conditioning, pressurization, pneumatic de-icing and engine starter.','*','A'),(535,3,'PNEUMATIC','THE AIR CONDITIONING AIR BLEED VALVES ARE:','A. Electrically controlled and pneumatically operated.','B. Electrically operated.','C. Pneumatically controlled.','*','A'),(536,3,'PNEUMATIC','THE AIR CONDITIONING BLEED AIR IS SUPPLIED BY:','A. Always by engine IS stage.','B. Always by engine HP stage.','C. Generally supplied by engine LP stage but if the air is not sufficient air surge is automatically switched to the engine HP stage (descent flight idle, ground operation).','*','C'),(537,3,'PNEUMATIC','WHAT HAPPENS, IN ABSENCE OF AIR PRESSURE, WITH ENGINE BLEED SELECTED \"ON\"?','A. Bleed valve stays open.','B. Bleed valve closes automatically.','C. Bleed valve must be closed manually.','*','B'),(538,3,'PNEUMATIC','TO USE THE AIR CONDITIONING IN HOTEL MODE OPERATION, YOU  NORMALLY USE:','A. Right ENG AIR BLEED plus right PACK VALVE only.','B. Right ENG AIR BLEED plus right PACK VALVE and, if you open the CROSS-FEED  BLEED VALVE the, left PACK VALVE.','C. Right ENG AIR BLEED plus right PACK VALVE and via the CROSS- FEED BLEED VALVE ( automatically opened ) the left PACK VALVE.','*','C'),(539,3,'PNEUMATIC','THE CROSS-FEED BLEED VALVE OPENS AUTOMATICALLY:','A. On ground, at least one engine running.','B. On ground, when BLEED AIR is supplied from the right engine in HOTEL MODE.','C. A + B are correct.','*','C'),(540,3,'PNEUMATIC','TO ENSURE A RAPID LEAK SENSING, A KEYLAR ENVELOPE IS  INSTALLED AROUND THE MAJOR PARTS OF THE HIGH TEMPERATURE  BLEED DUCT:','A. In the wing leading edge and wing fuselage firing.','B. In the upper and lower fuselage floor.','C. In the air conditioning pack area.','D. Answers A + B + C are correct.','D'),(541,3,'PNEUMATIC','AN OVERHEAT CONDITION DOWNSTREAM OF THE ENGINE BLEED AIR  SHUT-OFF VALVE CAUSES:','A. Actuation of the OVHT alert only.','B. Actuation of the OVHT alert and closure of ENG BLEED AIR VALVE, HP BLEED AIR  VALVE and associated PACK VALVE.','C. Actuation of the OVHT alert and closure of the ENG BLEED AIR VALVE only.','*','C'),(542,3,'PNEUMATIC','IN WHICH CASES DOES THE ENG BLEED VALVE CLOSE  AUTOMATICALLY?','A. Overheat, leak, or lack of air pressure.','B. Fire handle actuated, and during staffing sequence.','C. Propeller brake selected on for left bleed only.','D. Answers A+B+C are correct.','D'),(543,3,'PNEUMATIC','AFTER ILLUMINATION OF \"OVHT\" OR \"LEAK\" LIGHT, THE RELATED A  SYSTEM MAY BE RECOVERED:','A. For OVHT only after system cooling (no amber light).','B. For LEAK only (no amber light).','C. Never in any case.','*','A'),(544,3,'PNEUMATIC','THE FAULT BLEED LIGHT COMES ON AMBER AND THE \"CCAS\" INACTIVATED WHEN:','A. LEAK of air pressure only.','B. OVHT of air pressure only.','C. Disagreement between the valve and the selected position or in case of OVHT or LEAK.','*','C'),(545,3,'POWER','WHAT IS THE PURPOSE OF THE \"S\" BEND OF THE AIR INTAKE DUCT?','A. To provide uniform inlet airflow to the compressor.','B. To protect engine inlet in case of foreign object ingestion and to divide air flow in a   primary flow direct to the engine and secondary flow directed to the oil cooler.','C. A and B are correct.','*','C'),(546,3,'POWER','THE ACCESSORY GEAR BOX, WHICH IS DRIVEN BY THE \"HP SPOOL\",   CONTAINS DRIVES FOR:','A. The DC STARTER/GENERATOR and ACW GENERATOR.','B. The DC STARTER/GENERATOR, the fuel HP PUMP and the OIL PUMP.','C. The DC STARTER/GENERATOR, the ACW GENERATOR, the fuel HP PUMP and the OIL PUMP.','*','B'),(547,3,'POWER','ON THE PROPELLER REDUCTION GEAR BOX ARE INSTALLED:','A. The PROPELLER VALVE MODULE (PVM), the feather pump and over speed governor, the auxiliary feather pump and the ACW GEN.','B. The ACW GEN, the fuel HP PUMP, the PVM and the associated accessories.','C. Answer A, plus PROP BRAKE (RH engine) and the fuel cooled oil cooler.','*','C'),(548,3,'POWER','IS THE FUEL HEATED BEFORE \"HP PUMP\", TO PREVENT ICING?','A. Yes, by means self monitoring ECU (Electrical Control Unit).','B. No, it is not necessary.','C. Yes, by an automatic FUEL-HEATER installed at the filter outlet, heated by engine oil.','*','C'),(549,3,'POWER','HOW ARE THE OIL PRESSURE SURGES PREVENTED?','A. Air/oil cooler and pressure filter are both fitted with bypasses.','B. A \"cold relief valve\" bypasses the oil back to the tank, during cold weather start.','C. A and B are correct.','*','C'),(550,3,'POWER','THE ENGINE ELECTRONIC CONTROL (EEC) REGULATES ENGINE POWER AS A FUNCTION OF:','A. The power levers (PL) and PWR MGT selector, position.','B. Flight conditions and bleed air valves position.','C. A + B are correct.','*','C'),(551,3,'POWER','THE \"EEC\" FUNCTION IS:','A. To provide uptrim PWR in case of engine failure during take off, and ensure, at a given engine rating, a constant PL position.','B. To control, at low thrust level, and low speed, a constant propeller speed (for instance on ground).','C. A and B are correct.','*','C'),(552,3,'POWER','THE HYDRO-MECHANICAL UNIT (HMU) FUNCTIONS ARE:','A. To meter the fuel flow delivery to the engine.','B. To provide the motive flow to the fuel tank JET PUMP.','C. To provide the fuel shut-off function (controlled by CL).','D. All of the above are correct.','D'),(553,3,'POWER','THE PROPELLER BRAKE IS POWERED BY:','A. Hydraulic blue pressure.','B. Hydraulic green pressure.','C. A separate accumulator.','*','A'),(554,3,'POWER','WHAT IS THE LOGIC TO ENGAGE THE PROPELLER?','A. Gear shock absorber compressed and gust lock lever engaged.','B. Blue hydraulic pressure available (READY LT illuminates green).','C. Condition lever (CL) in fuel shut off or feather (NP signal below 22%).','D. All of the above are correct.','D'),(555,3,'POWER','WHAT HAPPENS IF THE BLUE HYD PRESSURE IS LOST DURING HOTEL MODE OPERATION?','A. Propeller brake remains engaged.','B. Propeller brake is released.','C. Propeller brake is unsafe and PROP BRK UNLK WARNING is activated.','*','A'),(556,3,'POWER','IS IT POSSIBLE TO USE PROPELLER BRAKE IN FLIGHT?','A. Yes always.','B. No.','C. Yes, but only in case of over speed.','*','B'),(557,3,'POWER','ARE THE TORQUE, ITT, NP, NH, FUEL FLOW/FUEL USED AND OIL PRESS/OIL TEMP GAUGES ALL AVAILABLE ON A BATTERY START?','A. Yes, all.','B. No, FUEL FLOW/FUEL USED and OIL PRESS/OIL TEMP require DC ELECT PWR; they become \"alive\" at 61.5 % NH during engine start','C. ITT and NH only.','*','B'),(558,3,'POWER','DURING START SEQUENCE, THE CROSS START SYSTEM:','A. Makes use of the opposite DC GEN to stan.','B. Makes use of the MAIN BAT until 10% NH.','C. Makes use of the MAIN BAT until 10% NH, then uses MAIN BAT and opposite DC GEN (on ground only).','*','C'),(559,3,'POWER','THE HIGH ENERGY IGNITION SYSTEM CONSISTS OF:','A. One ignition exciter and one spark igniter, for each engine, powered by DC BUS 1 or 2.','B. Two ignition exciters (A and B., for each engine, powered by DC ESS BUS and two spark igniters, one for each ignition exciter.','C. One ignition exciter, for each engine, powered by DC ESS BUS and two spark igniters, for each ignition exciter.','*','B'),(560,3,'POWER','WHEN \"ENG START\" ROTARY SELECTOR IS IN START A OR B POSITION:','A. Exciter is powered when fuel shut-off valve is open (CL feather).','B. Starter and exciter are automatically deactivated when NH reaches 45%.','C. A + B are correct.','*','C'),(561,3,'POWER','WHEN ENG Start ROTARY SELECTOR IS IN \"CRANK\" POSITION THE EXCITERS ARE ENERGIZED:','A. With CL at fuel shut-off position.','B. With CL at a position different than fuel shut-off.','C. Never.','*','C'),(562,3,'POWER','THE EXCITERS A + B , FOR EACH ENGINE, ARE AUTOMATICALLY ACTIVATED:','A. if TQ (torque) drops below 60%.','B. If NH drops below 60%.','C. If NH drops below 30%.','*','B'),(563,3,'POWER','THE USE OF MANUAL IGNITION (MAN IGN PB ON) ENERGIZES THE EXCITERS ON BOTH ENGINES:','A. In case of adverse weather operations or EEC failure.','B. if NH drops below 30% in one engine.','C. After an ATPCS sequence.','*','A'),(564,3,'POWER','ON GROUND WITH GUST LOCK ENGAGED, WHAT IS THE MAXIMUM POWER AVAILABLE?','A. Ground idle.','B. Flight idle.','C. A few degrees below fight idle.','D. Max. take-off power.','C'),(565,3,'POWER','21. WHICH \"ATPCS\" FUNCTIONS ARE AVAILABLE WHEN IT HAS BEEN ARMED FOR TAKE-OFF?','A. Up-trim only.','B. Auto-feather only.','C. Up-trim and auto-feather.','*','C'),(566,3,'POWER','AIRCRAFT ON GROUND, \"PWR MGT ON T.O.\", ATPCS PUSH-BUTTON ON, \"ATPCS\" IS ARMED IF:','A. Both PL above 49┬░ and both torque above 46%.','B. Both PL above 56┬░ and both CL on max. RPM.','C. Both PL above 56┬░ and both torque above 90%.','*','A'),(567,3,'POWER','WHEN THE \"PWR MGT\" IS SET IN TAKE-OFF POSITION : WHAT IS INDICATED BY THE TWO \"AMBER TARGET BUGS\" ON THE TORQUE GAUGES?','A. PWR MGT amber bugs are set by FDAU (flight data acquisition unit) to the reserve  take-off power setting (up-trim value).','B. PWR MGT amber bugs are set by FDAU (flight data acquisition unit) to the normal take off power setting (take-off value).','C. PWR MGT amber bugs are not indicating with PWR MGT in TO position.','*','A'),(568,3,'POWER','AFTER A NORMAL TAKE-OFF, HOW IS \"ATPCS\" USUALLY DISARMED?','A. When the PL are retarded for climb.','B. When the CL are retarded for climb.','C. When the PWR MGT selector is moved from T.O. position.','*','C'),(569,3,'POWER','A \"GATE\" PREVENTS \"PL\" ANGLE REDUCTION BELOW FLIGHT IDLE:','A. In flight as soon as both main landing gear absorbers are released.','B. In flight as soon as the landing gear lever is selected up.','C. In fight as soon as the landing gear is up and locked.','*','A'),(570,3,'POWER','THE PEC (PROPELLER ELECTRONIC CONTROL) IS A DUAL CHANNEL ELECTRONIC BOX, WHICH PROVIDES:','A. The syncro-phasing between the two propellers by a closed loop control over the  propeller pitch change system.','B. To detect, isolate and accommodate systems fault.','C. A + B are correct.','*','C'),(571,3,'POWER','THE PROPELLER PITCH CHANGE IS HYDRO-MECHANICALLY CONTROLLED BY:','A. Propeller valve module (PVM).','B. Propeller control unit (PCU).','C. Propeller electron control (PEC).','*','A'),(572,3,'POWER','DURING GO AROUND WITH TWO ENGINES OPERATING, THE \"ATPCS\":','A. Is armed because the torque gages are above 53%.','B. Is armed, provided that the PWR MGT selector is set at T.O. position, but only for auto-  feathering.','C. Is not armed.','*','B'),(573,3,'POWER','DURING LANDING, WHEN DOES THE IDLE-GATE MOVE REARWARD TO ALLOW THE \"GROUND IDLE\" POSITION?','A. As soon as one landing gear shock absorber is compressed.','B. Only after both main landing gear shock absorbers are compressed.','C. Only after all landing gear shock absorbers are compressed.','*','A'),(574,3,'POWER','STARTER FAULT LIGHT illuminates WHEN:','A. An GCU failure is detected.','B. On right engine, ENG START selector is on START, propeller brake is on, but gust lock is not engaged.','C. Starter remains engaged after 45% NP.','D. A+B+C are correct.','D'),(575,3,'POWER','AT TAKE-OFF, WHAT HAPPENS IF AN \"EEC\" FAULT OCCURS.','A. Power is drastically reduced; unless the power lever of the related engine is moved  forward.','B. Power remains virtually unchanged due to a fail-fix device, EEC fault light flashes and EEC deselection is strictly prohibited.','C. The related engine may surge beyond torque limits.','*','B'),(576,3,'POWER','IN CASE OF AN \"EEC\" FAULT:','A. When PL is retarded below 52┬░ EEC fault light illuminates steady.','B. With PL below 52┬░, after EEC deselection, PL is active again and it follow HMU base law.','C. Both A and B are correct','*','C'),(577,3,'POWER','HOW IS A FARED ENGINE DETECTED BY THE \"ATPCS\"?','A. When one torque gage drops below 21%.','B. When one oil pressure falls below 8 PSI.','C. When NP goes below 60% with the related power lever above flight idle.','*','A'),(578,3,'POWER','UPTRIM LIGHT ILLUMINATES DURING TAKE-OFF WHEN ONE ENGINE FAR, TO INDICATE:','A.  That the pilot has increase torque on the other engine','B. That the ATPCS has automatically increased torque (10% of power) on the live engine.','C. That the PWR MGT selector has to be set on MCT.','*','B'),(579,3,'POWER','AUTO-FEATHERING OCCURS.','A.  Immediately when torque drops below 18%','B. Only when PL is retarded.','C. After 2.15 seconds following a torque drop below 18%.','*','C'),(580,3,'POWER','THE DELAY FROM THE TIME AN ENGINE FAILURE IS SENSED, UNTIL THE INITIATION OF AUTO-FEATHERING, ALLOW THE ACCELERATE. STOP PHASE OF A TAKE-OFF TO BENEFIT FROM SOME REVERSING ACTION ON THE FAILED ENGINE.','A. True.','B. False.','C.','*','A'),(581,3,'POWER','IF AN ENGINE FAILURE OCCURS BEFORE Vi AND BOTH PL ARE RETARDED WITHIN 2.15 SECONDS, WHEN DOES \"ATPCS\" DISARM?','A. At the initiation of uptrim..','B. At least one PL is retarded below 49┬░, or both torque reading are below 46%.','C. At the initiation of auto-feathering','*','B'),(582,3,'POWER','DURING AN \"ATPCS\" ENGINE FAILURE SEQUENCE, WHEN DOES THE \"ARM\" LIGHT EXTINGUISH?','A. At UPTRIM','B. Auto-feather signal triggered on failed engine.','C. It doesnt extinguish unless the PWR MGT selector is out of  T.O. position.','*','B'),(583,3,'POWER','HOW IS A FAILED ENGINES PROPELLER FEATHERED BY THE \"ATPCS\"?','A. Via an electrical signal to the electric feathering pump.','B. By an electrical motor which drives the blades to the feather stop.','C. A propeller can only be feather by \"ATPCS\", if the related CL is in feather position.','*','A'),(584,3,'POWER','SEQUENCE AFTER ATPCS TRIGGERING:','A. The trigger cancellation can only result from, PWR MGT other then TO, ATPCS PB set to   off, both PL retarded.','B. If the engine is restarted, it will be necessary to select PWR MGT at MCT position after relight, in order to unfeather the propeller.','C. A + B are correct.','*','C'),(585,3,'POWER','IN THE EVENT OF A FAILURE OF PRIMARY CHANNEL IN PEC SYSTEM:','A. The propeller electronic control is lost.','B. The control of the propeller system will be automatically transferred to the back-up channel.','C. The control of the propeller system will be transferred by using PEC FAULT PB.','*','B'),(586,3,'POWER','THE CORRECT WORKING OF THE BACK-UP CHANNEL IS CONFIRMED:','A. On ground, at each propeller unfeathering by SGL CH light on for 2 seconds.','B. On ground at each propeller unfeathering by LO Pitch light illumination.','C. By selecting off the primary channel for test','*','A'),(587,3,'POWER','WHEN THE PEC FAULT LIGHT ILLUMINATES AMBER, SELECTING OFF THE RELEVANT PB:','A. The control of the propeller system will be automatically transferred to the back-up channel.','B. PEC is deactivated and NP depends of PWR MGT position.','C. PEC is deactivated and NP is blocked at 102.5% when PL is sufficient','*','C'),(588,3,'PRESSURITATION','HOW MANY OUTFLOW VALVES ARE THERE?','A. Two: one electro-pneumatic and one pneumatic outflow valves.','B. Two electro-pneumatic outflow valves.','C. Two pneumatic outflow valves.','*','A'),(589,3,'PRESSURITATION','THE PNEUMATIC OUTFLOW VALVE:','A. Is always slaved to the electro-pneuinatic outflow valve.','B. Operates in manual mode only.','C. Is slaved to the electro-pneumatic outflow valve in automatic mode only.','*','C'),(590,3,'PRESSURITATION','IN NORMAL OPERATION, WITHOUT FAILURE, THE DIGITAL CONTROLLER USES AS REFERENCE THE AIRCRAFT STATIC AIR PRESSURE GENERATED BY:','A. ADC 1 and CM 1 altimeter BARO setting.','B. ADC 2 and CM 1 altimeter BARO setting.','C. ADC 1 and 1013 HPa.','*','A'),(591,3,'PRESSURITATION','WHAT ARE THE CORRECT INDICATIONS DURING A PRESSURIZATION SYSTEM TEST?','A. The amber FAULT light in the MAN PB.','B. Only the landing elevation indicator displays alternatively 18800 and - 8800.','C. A + B and the test is inhibited in flight.','*','C'),(592,3,'PRESSURITATION','IF AUTOMATIC PRESSURIZATION CONTROL IS DESIRED, IN WHICH POSITION SHOULD THE \"MAN RATE KNOB\" BE PLACED:','A. NORM.','B. AUTO.','C. 9 oClock position.','*','A'),(593,3,'PRESSURITATION','WHAT DO YOU SET IN \"AUTO PRESS PANEL\" BEFORE EACH FLIGHT?','A. Departing airport field elevation, using QNH or zero if using QFE.','B. Landing airport field pressure altitude.','C. Landing airport field elevation, using QNH or zero if using QFE.','*','C'),(594,3,'PRESSURITATION','HOW HIGH ABOVE TAKE OFF ELEVATION CAN THE AIRCRAFT BE OPERATED WITHOUT CANCELING THE \"AUTOMATIC RETURN\"  FEATURE?','A. 3500 feet above landing field elevation.','B. 2500 feet on QNE (1013).','C. 3500 feet above take off field elevation.','*','C'),(595,3,'PRESSURITATION','THE MAX CABIN RATE OF CLIMB, UP TO 20000 FT IN AUTO MODE IS:','A. +550 ft/mm.','B. +400 ft/min.','C. -500 ft/min.','*','A'),(596,3,'PRESSURITATION','WHAT IS THE MAXIMUM CABIN DIFFERENTIAL PRESSURE?','A. Positive 6.35 PSI, limited by a manometric capsule.','B. Negative 0.5 PSI, limited by a non return valve.','C. A + B are correct.','*','C'),(597,3,'PRESSURITATION','WHAT IS THE MAXIMUM CABIN ALTITUDE (FL25O DIFF. PRESS. 6 PSI)?','A. 10000 ft.','B. 6740 ft.','C. 7640 ft.','*','B'),(598,3,'PRESSURITATION','HOW IS THE SYSTEM PROTECTED AGAINST EXCEEDING THE MAXIMUM  CABIN DIFFERENTIAL PRESSURE?','A. Both outflow valves incorporate an electrically driven torque motor designed to fully open   the valve.','B. Both outflow valves incorporate a manometric capsule (aneroid) to hold the valve open sufficiently to prevent overpressure.','C. Only the electro-pneumatic valve incorporates a manometric capsule to hold the valve open  sufficiently to prevent overpressure.','*','B'),(599,3,'PRESSURITATION','IN AUTO, WHAT IS THE HIGHEST CABIN RATE OF DESCENT AVAILABLE WITH THE DESCENT RATE PUSH-BUTTON RELEASED (NORM)?','A. - 400 ftl min.','B. - 500 ft/mm.','C. - 550 ft/ruin.','*','A'),(600,3,'PRESSURITATION','IN AUTO, WHAT IS THE HIGHEST CABIN RATE OF DESCENT AVAILABLE  WITH THE DESCENT RATE PB DEPRESSED (FAST)?','A. -400 ft/MIN.','B. -500 ft/MIN.','C. -550 ft/MIN.','*','B'),(601,3,'PRESSURITATION','BEFORE LANDING TO AVOID A CABIN PRESSURE BUMP AT TOUCH  DOWN, THE CABIN ALTITUDE IS AUTOMATICALLY MAINTAINED AT 300 FT BELOW:','A. Aircraft altitude.','B. Theoretical cabin altitude.','C. Selected landing elevation.','*','C'),(602,3,'PRESSURITATION','AFTER LANDING, THE CABIN DEPRESSURIZATION RATE IS:','A. +450 ft/min.','B. +550 ft/min.','C. +300 ft/min.','*','B'),(603,3,'PRESSURITATION','IN CASE OF \"ADC 1\" FAILURE, THE DIGITAL CONTROLLER USES AS  REFERENCE AIRCRAFT STATIC AIR PRESSURE GENERATED BY:','A. ADC 2 and CM 1 altimeter BARO setting.','B. ADC 2 and CM 2 altimeter BARO setting.','C. ADC 2 and 1013 MBAR.','*','C'),(604,3,'PRESSURITATION','WHAT IS THE CORRECT WAY TO SWITCH FROM AUTOMATIC TO  MANUAL OPERATION?','A. Select MAN the CABIN PRESS PB turn the MAN RATE KNOB to 9 oclock position  and operate the MAN RATE KNOB as required.','B. Turn the MAN RATE KNOB to 9 oclock position, select MAN the CABIN PRESS PB  and operate the MAN RATE KNOB as required','C. Select MAN the CABIN PRESS PB and operate the MAN RATE KNOB as required.','*','B'),(605,3,'PRESSURITATION','IN \"MAN MODE\", WHAT IS THE HIGHEST CABIN RATE OF DESCENT AND  CLIMB AVAILABLE?','A. -1500 ft/min; +2500 ft/min','B. -2500ft/min;+1500ft/min.','C. -500 ft/min; + 1000 ft/mm.','*','A'),(606,3,'PRESSURITATION','HAT IS THE CORRECT WAY TO SWITCH FROM MANUAL TO  AUTOMATIC OPERATION?','A. Select to AUTO MODE the CABIN PRESS PB and turn the MAN RATE KNOB  smoothly to normal position.','B. Turn the MAN RATE KNOB to NORM position and select to AUTO MODE the CABIN  PRESS PB.','C. It is not possible.','*','A'),(607,3,'PRESSURITATION','WHAT HAPPENS IN CASE OF LOSS OF ELECTRICAL SUPPLY TO THE  \"DIGITAL CONTROLLER\", IN AUTOMATIC MODE?','A. Both outflow valves remain in the last position.','B. Both outflow valves go to full open.','C. Both outflow valves go to full close.','*','C'),(608,3,'PRESSURITATION','IN CASE OF TOTAL DC ELECTRICAL POWER LOST:','A. AUTO PRESS mode is lost','B. MANUAL PRESS mode and CABIN PRESS ND are still available.','C. A + B are correct.','*','C'),(609,3,'PRESSURITATION','THE \"CCAS\" SYSTEM IS ACTIVATED WHEN THE CABIN ALTITUDE  REACHES:','A. 6740 ft.','B. 11000 ft.','C. 10000 ft.','*','C'),(610,3,'PRESSURITATION','WHEN IS THE \"DUMP\" FUNCTION AVAILABLE?','A. On ground only, MAN or AUTO PRESS mode.','B. It only works in AUTO PRESS mode.','C. It only works in AUTO PRESS mode, if differential pressure is below 1 PSI.','*','B'),(611,3,'PRESSURITATION','HOW MANY OUTFLOW VALVES ARE OPENED IN \"DUMP\" FUNCTION?','A. Only the pneumatic valve.','B. Only the electro-pneumatic valve.','C. Both.','*','C'),(612,3,'PRESSURITATION','SELECTING THE \"DITCH MODE\" WITH THE \"DITCH PB\":','A. Two electrical motors maintain both outflow valves in closed position, regardless of AUTO  or MANUAL PRESS mode use.','B. In addition to the white light on DITCH PB, MASTER CAUTION flashes amber and AIR amber light illuminates on CAP.','C. A + B are correct.','*','C'),(613,3,'VENTILATION','HOTEL MODE NORMAL OPERATION, THE VENTILATION PANEL BEING IN AUTO CONFIGURATION:','A. The OVBD valve is closed, the U/F valve is opened.','B. The OVBD valve is opened, the U/F valve is closed.','C. Both valves are opened.','*','B'),(614,3,'VENTILATION','THE OVERBOARD VALVE POSITION CAN BE SELECTED MANUALLY, USING \"OVBD VALVE\" OVERRIDE CIT SWITCH:','A. After AUTO mode failure.','B. On ground for cold days use, in order to accelerate cabin heating selecting full close  position.','C. A + B are correct.','*','C'),(615,3,'VENTILATION','WHEN LH ENGINE START SEQUENCE IS INITIATED:','A. Extract fan stops during 10 seconds.','B. Extract fan stops during 120 seconds, to avoid pressure shocks, and exhaust mode FAULT  illuminates.','C. Extract fan stops during 120 seconds, to avoid pressure shocks, and exhaust mode FAULT  doesnt illuminate.','*','B'),(616,3,'VENTILATION','THE \"OVBD\" VALVE \"CTL\" SWITCH ON AUTO, THE \"OVBD\" VALVE  POSITION IS FUNCTION OF:','A. The exhaust mode PB position.','B. The aircraft condition (flight or ground, ENG 1 running or not).','C.  A + B are correct','*','C'),(617,3,'VENTILATION','WHEN SHOULD THE AVIONICS VENT SYSTEM EXTRACT FAN STOP?','A. For 120 seconds after ENG 1 start.','B. When OVBD is selected on the EXHAUST MODE PB.','C. A + B are correct.','*','C'),(618,3,'VENTILATION','AIRCRAFT IN FLIGHT, OR ON GROUND TWO ENGINES RUNNING, WHAT   ARE THE NORMAL POSITIONS OF THE \"OVBD\" AND  UNDERFLOOR VALVES?','A. OVBD fully closed, UNDERFLOOR fully closed.','B. OVBD fully closed, UNDERFLOOR fully open.','C. OVBD fully open, UNDERFLOOR fully closed.','*','B'),(619,3,'VENTILATION','THE EXHAUST MODE \"PB\" IS ON \"OVBD\", ACTING ON THE \"OVBD  VALVE CONTROL SWITCH:','A) You can change the position of the valve.','B) You cannot change the position of the valve.','C) You can only open the valve.','*','A'),(620,3,'VENTILATION','\"EXHAUST MODE\" FAULT PB IS ILLUMINATED IN CASE OF:','A. OVBD valve position disagreement with associated control','B. Fan failure or over temperature and CCAS is activated.','C. U/F valve position disagrees with associated control','*','B'),(621,3,'VENTILATION','WHEN SHOULD THE EXHAUST MODE PB BE SET ON \"OVBD\"?','A. In case of an extract fan failure on ground.','B. In case of an extract fan failure in flight.','C. For all ground operations.','*','B'),(622,3,'VENTILATION','IN FLIGHT WITH AN EXTRACT FAN FAILURE, AVIONICS VENTILATION CAN BE PERFORMED BY SELECTING \"OVBD\" EXHAUST MODE  PUSH BUTTON:','A. This assertion is correct, regardless of the OVBD valve position.','B. Correct assertion, providing the OVERED valve is on auto position.','C. Correct assertion, providing differential pressure is below 1 PSI','*','B'),(623,3,'VENTILATION','IN FLIGHT, THE EXHAUST MODE PB ON \"OVBD\" POSITION, AND THE CONTROL SWITCH ON \"AUTO\" MODE:','A. Extract fan is off, U/F valve is close, OVBD valve is partially open.','B. Extract fan is off, U/F valve is partially close, OVBD valve is partially open.','C. Extract fan is on, U/F valve is close, OVBD valve is partially open.','*','A'),(624,3,'VENTILATION','ILLUMINATION OF THE AVIONICS VENT PANEL EXHAUST MODE  PUSH-BUTTON \"OVBD\" LIGHT, CAUSES THE GROUND MECHANIC CALL  HORN TO SOUND:','A. Always on ground.','B. When differential pressure is 1 PSI.','C. On ground and in flight','*','A'),(625,3,'VENTILATION','ON THE AVIONICS VENT PANEL, THE \"FAULT\" LIGHT ILLUMINATES AMBER WHEN:','A. On ground engine 1 not running, OVBD valve is not fully open, (except wit OVBD VALVE on full close position).','B. In flight or on ground 2 engines running, OVBD valve is not fully close, (except wit OVBD VALVE on full open position).','C. There is any disagreement between the valve and te switch.','D. A+B+C are correct.','D'),(626,3,'VENTILATION','WHAT IS THE MAX DIFF. PRESS. ALLOWED TO SELECT THE \"OVBD VALVE\" TO FULL OPEN POSITION?','A. 1 PSI.','B. 0.5 PSI.','C. 2 PSI','*','A'),(627,3,'COMMUNICATIONS','The Remote Control Audio Unit (RCAU) contains:','A. One electronic processor for the flight compartment and one electronic processor for the cabin','B. An electronic processor for each cockpit crew member','C. Two electonic processor which controls all internal and external communications','*','B'),(628,3,'COMMUNICATIONS','The Cockpit Voice recorder (CVR) enables:','A. Recording of conversations received and transmitted by the crew members, announcements made to passengers as well as aural warnings','B. Recording of conversations receveid and transmitted by the crew members only','C. Recording of external conversations of the crew memers only','*','A'),(629,3,'COMMUNICATIONS','AUDIO 1/2 SEL pushbuttons :','A. control functioning of associated RCAU processing boards','B. if released, comes on ALTN white legend and FAULT amber legend extinguishes, affected crew station is connected directly to VHF1 (if CAPT affected) or VHF2 (if F/O affected','C. a) + b) are correct','*','C'),(630,3,'COMMUNICATIONS','The Emergency Locator Transmitter (ELT) is able to transmit','A. a distress signal on 121.5 MHz and 243 MHz frequencies','B. a distress signal on 121.5 MHz and 243 MHz frequencies and a geographical position signal on 406.025 MHz frequency','C. a distress signal on 116.5 MHz and 233 MHz frequencies and a geographical position signal on 406.025 MHz frequency','*','B'),(631,3,'COMMUNICATIONS','The sound level :','A. is preset for CCAS, GPWS and TCAS alerts','B. can be regulated from the Audio Control Panels for all communications systems','C. a) + b) are correct','*','C'),(632,3,'COMMUNICATIONS','With ALT 1/2 SEL pushbutton in ALTN :','A. Passenger Address, interphone and other VHF cannot be used on the affected side','B. Passenger Address and interphone are usable, other VHF cannot be used on the affected side','C. Passenger Address is usable, interphone and other VHF cannot be used on the affected side','*','A'),(633,3,'GENERAL','In the cargo door panel the blue light ÔÇ£cargo door armedÔÇØ is ON when :','A. the cargo door is opening','B. the Actuator Selector Switch working conditions are met (panel cover opened, all door hooks disengaged)','C. the cargo door opening system is supplied from GPU','*','B'),(634,3,'GENERAL','Cockpit lights indication philosophy :','A. WHITE ÔÇô control position indication, neutralized abnormal configuration ; GREEN ÔÇô normal operation (flashing lights)','B. WHITE ÔÇô control position indication, neutralized abnormal configuration ; GREEN ÔÇô normal operation ; BLUE ÔÇô normal transient configuration (to be switched off)','C. WHITE ÔÇô control position indication, neutralized abnormal configuration ; GREEN ÔÇô normal operation ; BLUE ÔÇô normal transient configuration','*','C'),(635,3,'GENERAL','Taxi and T.O. lights :','A. automatically extinguish when landing gear lever comes up','B. must be switched off after take off together with landing lights','C.automatically extinguish when the aircraft reaches 500 ft','*','A'),(636,3,'GENERAL','External lights switches :','A.NAV ÔÇô controls 3 navigation lights (1 red, 1 green, 1 white)','B. BEACON ÔÇô control 2 white flashing lights','C. a) + b) are correct','*','C'),(637,3,'GENERAL','Hotel Mode conditions :','A. right engine running + prop brake on + condition levers at feather + right power lever at F.I.','B. right engine running + prop brake on + gust lock on + condition levers at feather','C. right engine running + prop brake on + condition levers at feather','*','B'),(638,3,'GENERAL','ATR42 external dimensions are :','A. length = 25,74 m ; span = 24,572 m ; height = 9,00 m','B. length = 22,67 m ; span = 26,50 m ; height = 9,00 m','C. length = 22,67 m ; span = 24,572 m ; height = 7,59 m','*','C'),(639,3,'GENERAL','Doors SW TEST pushbutton :','A. enables to test the microswitches system on cabin and service door and illuminates green lights CAB OK and SVCE OK if doors are open and associated microswitches are in unlocked position (on ground)','B. enables to test the microswitches system on cabin and service door and illuminates green lights CAB OK and SVCE OK to verify a UNLK indication on the doors panel (in flight)','C. a) + b) are correct','*','A'),(640,3,'FUEL','Where is the refuel/defeul panel ?','RH main landing gear fairing','LH main landing gear fairing','Below CAPT window','*******************','A'),(641,3,'FUEL','What power source supplies the refuel/defuel panel ?','DC SVCE BUS','DC GROUND HANDLING BUS','DC BUS 1 form HOT MAIN BAT BUS','*******************','B'),(642,3,'FUEL','With the BAT switch OFF and no external power, what is required to power the refuel/defuel panel ?','Turn the BAT switch ON','Press DC SVCE BUS push-button, on the cabin attendant panel','Open the refuel/defuel panel door','*******************','C'),(643,3,'FUEL','Refuel/defuel system :','In case of FQI failure detection, the high level is achieved by a level sensor installed at the bottom of each surge tank','The wing tanks can also be refueled by gravity','The system may be used to defuel the A/C by applying a 0.77 bar (11 PSI) suction to the connector and opening the tank refuel valves','A + B + C are correct','D'),(644,3,'FUEL','With the refuel/defuel panel mode selector switch at refuel position, how are the refuel valves operated ?','By automatic logic if the refuel valves switches are set on NORM','By manual selection of the refuel valves switches to OPEN or SHUT','A + B are possible','*******************','C'),(645,3,'FUEL','When the refuel/defuel panel \"FQI TEST\" push-button is depressed, what are the correct indications ?','display all 8 only on the refuel/defuel panel fuel quantity gauges','display all 8 on the refuel/defuel panel and cockpit fuel quantity gauges','Both LH and RH REFUEL VALVES shut down plus CCAS is activated','B + C are correct','D'),(646,3,'FUEL','Fuel quantity indicating system :','the left and right fuel quantity indicating channels are independent','In a level attitude (within -3┬░ and +1┬░ of pitch and ┬▒2┬░ of roll), the accuracy of the 5 probes fuel quantity indicating system in each tank is ┬▒1% near ZERO and ┬▒3% at FULL','A + B are correct','*******************','C'),(647,3,'FUEL','How many magnetic level indicators are located on the bottom of each fuel tank ?','One','Two','There is no magnetic level indicator in fuel tank','*******************','B'),(648,3,'NAVIGATION','Aircraft supplied by batteries only :','VHF NAV n.1 and VHF NAV n.2 are still operating','VHF NAV n.1 only is still operating','VHF NAV n.1 only, on the last selected frequency, is still operating','*******************','B'),(649,3,'NAVIGATION','The Marker Beacon Receiver gives :','A visual signal displayed at the bottom RH corner of the EADI','Audio signal','A + B are correct','*******************','C'),(650,3,'NAVIGATION','Flying over Toulouse airport (elevation 500 ft) at 3500 feet on QNH, what is the radio altimeter indication on EADI ?','3000 ft','Nothing, RADIO ALT altitude is not displayed above 2500 ft','Amber dashes','*******************','B'),(651,3,'NAVIGATION','Decision Height (DH) indications occur :','When aircraft radio altitude becomes lower than selected DH +100 ft, a white box appears on EADI','When aircraft radio altitude becomes lower than selected DH a DH amber symbol comes inside the box','A + B are correct','*******************','C'),(652,3,'NAVIGATION','The Ground Proximity Warning System (GPWS) provides :','Visual and aural alert in case of dangerous flight','Alerts between 50 and 2500 ft AGL only','Test on ground and in flight (above 1000ft RA), by pressing one of the GPWS/GS pb','A + B + C are correct','D'),(653,3,'NAVIGATION','When can the GPWS glide slope warning be inhibited ?','Anytime, by selecting the GPWS switch to FLAPS OVERRIDE','Below 1000 ft AGL by pressing one of the GPWS/GS switch','By selecting flaps 30┬░ with gear down','*******************','B'),(654,3,'NAVIGATION','What audio alert is triggered when descending through the selected DH with the gear extended ?','None, the alert sound only with gear UP','Minimums-minimums','Approaching minimums','*******************','B'),(655,3,'NAVIGATION','The weather radar detection is displayed on :','The EHSI selected in FULL (ROSE) MODE only','The EHSI selected in ARC MODE only','The EHSI selected in FULL or ARC MODE','*******************','B'),(656,3,'NAVIGATION','When you check the Weather Radar working in test position :','The range is automatically selected at 100 NM','Three arcs appear on EHSI (green, yellow, red) plus an arc predominately green between 85 and 95 NM','A + B are correct plus selected mode appears on the top LH of EHSI','*******************','C'),(657,3,'NAVIGATION','When will the selection of the \"TGT\" mode on weather radar control panel activate the amber \"TGT\" advice on the EHSI ?','Anytime a yellow radar return is within 50 NM and 20┬░ of heading','Anytime a level 3 (red) radar return is between 60 and 120 NM and within 7.5┬░ of heading','Anytime a black radar return appears within 10┬░ of heading and is located between 30 and 75 NM away','*******************','B');
